// ΓöÇΓöÇΓöÇ Confetti Particle System ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
interface Particle {
    id: number;
    x: number;
    y: number;
    size: number;
    color: string;
    rotation: number;
    velocityX: number;
    velocityY: number;
    rotationSpeed: number;
    opacity: number;
    shape: "circle" | "rect" | "star";
}

const CONFETTI_COLORS = [
    "#FF6B6B", "#4ECDC4", "#45B7D1", "#FDCB6E",
    "#6C5CE7", "#FF85A2", "#2ECC71", "#F39C12",
    "#E74C3C", "#3498DB", "#1ABC9C", "#9B59B6",
];

function ConfettiCanvas() {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const particlesRef = useRef<Particle[]>([]);
    const animFrameRef = useRef<number>(0);
    const burstCountRef = useRef(0);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext("2d");
        if (!ctx) return;

        const resize = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        };
        resize();
        window.addEventListener("resize", resize);

        const createBurst = (count: number) => {
            const particles: Particle[] = [];
            for (let i = 0; i < count; i++) {
                const angle = (Math.random() * Math.PI * 2);
                const speed = 4 + Math.random() * 8;
                particles.push({
                    id: Date.now() + i,
                    x: canvas.width / 2 + (Math.random() - 0.5) * 200,
                    y: canvas.height * 0.35,
                    size: 4 + Math.random() * 8,
                    color: CONFETTI_COLORS[Math.floor(Math.random() * CONFETTI_COLORS.length)],
                    rotation: Math.random() * 360,
                    velocityX: Math.cos(angle) * speed,
                    velocityY: Math.sin(angle) * speed - 6,
                    rotationSpeed: (Math.random() - 0.5) * 10,
                    opacity: 1,
                    shape: (["circle", "rect", "star"] as const)[Math.floor(Math.random() * 3)],
                });
            }
            particlesRef.current.push(...particles);
        };

        // Initial burst
        createBurst(80);

        // Additional bursts
        const burstTimers = [
            setTimeout(() => createBurst(50), 300),
            setTimeout(() => createBurst(40), 700),
            setTimeout(() => createBurst(30), 1200),
        ];

        const drawStar = (ctx: CanvasRenderingContext2D, x: number, y: number, size: number) => {
            ctx.beginPath();
            for (let i = 0; i < 5; i++) {
                const angle = (i * 4 * Math.PI) / 5 - Math.PI / 2;
                const method = i === 0 ? "moveTo" : "lineTo";
                ctx[method](x + Math.cos(angle) * size, y + Math.sin(angle) * size);
            }
            ctx.closePath();
            ctx.fill();
        };

        const animate = () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            const alive: Particle[] = [];

            for (const p of particlesRef.current) {
                p.x += p.velocityX;
                p.y += p.velocityY;
                p.velocityY += 0.12; // gravity
                p.velocityX *= 0.99; // friction
                p.rotation += p.rotationSpeed;
                p.opacity -= 0.004;

                if (p.opacity <= 0 || p.y > canvas.height + 20) continue;
                alive.push(p);

                ctx.save();
                ctx.globalAlpha = p.opacity;
                ctx.translate(p.x, p.y);
                ctx.rotate((p.rotation * Math.PI) / 180);
                ctx.fillStyle = p.color;

                if (p.shape === "circle") {
                    ctx.beginPath();
                    ctx.arc(0, 0, p.size / 2, 0, Math.PI * 2);
                    ctx.fill();
                } else if (p.shape === "rect") {
                    ctx.fillRect(-p.size / 2, -p.size / 4, p.size, p.size / 2);
                } else {
                    drawStar(ctx, 0, 0, p.size / 2);
                }
                ctx.restore();
            }

            particlesRef.current = alive;

            if (alive.length > 0) {
                animFrameRef.current = requestAnimationFrame(animate);
            }
        };

        animFrameRef.current = requestAnimationFrame(animate);

        return () => {
            window.removeEventListener("resize", resize);
            cancelAnimationFrame(animFrameRef.current);
            burstTimers.forEach(clearTimeout);
        };
    }, []);

    return (
        <canvas
            ref={canvasRef}
            className="fixed inset-0 z-50 pointer-events-none"
            style={{ width: "100vw", height: "100vh" }}
        />
    );
}

