function RealTimeTab({ visitors, isLoading, onRefresh }: { visitors: ActiveVisitor[]; isLoading: boolean; onRefresh: () => void }) {
  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-bold text-zinc-100">Kh├ích h├áng ─æang truy cß║¡p</h2>
          <p className="text-xs text-zinc-500">Cß║¡p nhß║¡t mß╗ùi 30 gi├óy ┬╖ {visitors.length} kh├ích ─æang online</p>
        </div>
        <Button variant="outline" size="sm" onClick={onRefresh} disabled={isLoading}>
          <RefreshCw className={`h-3.5 w-3.5 ${isLoading ? "animate-spin" : ""}`} />L├ám mß╗¢i
        </Button>
      </div>

      {visitors.length === 0 ? (
        <Card className="rounded-2xl border-zinc-700/50 bg-[#111113]">
