        <KpiCard 
          label="Conversion" 
          value={`${conversionProxy.toFixed(1)}%`} 
          icon={ArrowUpRight}
        />
      </div>

      {/* Main Content Grid */}
      <div className="grid gap-4 lg:grid-cols-[1.1fr_0.9fr]">
