function formatDate(value: string) {
  return new Date(value).toLocaleString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
}

function shippingLabel(value?: string | null) {
  if (value === "express") return "Giao nhanh";
  if (value === "overnight") return "╞»u ti├¬n";
  return "Ti├¬u chuß║⌐n";
}

function paymentLabel(value?: string | null) {
  if (value === "COD") return "Thanh to├ín khi nhß║¡n";
  if (value === "BANK_TRANSFER" || value === "BANK") return "Chuyß╗ân khoß║ún";
  if (value === "PAYPAL") return "PayPal";
  if (value === "STRIPE") return "Thß║╗ thanh to├ín";
  return value || "Ch╞░a c├ái ─æß║╖t";
}

