                </div>
              </CardContent>
            </Card>

            {events.length > 0 && (
              <Card className="rounded-[2.25rem] border-zinc-700/50 bg-[#111113] shadow-sm">
                <CardContent className="p-6 lg:p-8">
                  <div className="flex items-center gap-3">
                    <FileText className="h-5 w-5 text-primary" />
                    <h2 className="text-2xl font-black tracking-tight text-zinc-100">Lß╗ïch sß╗¡ trß║íng th├íi</h2>
                  </div>
                  <div className="mt-6 space-y-5">
                    {events.map((event, index) => {
                      const meta = STATUS_OPTIONS.find((item) => item.value === event.status) || STATUS_OPTIONS[0];
                      const EventIcon = meta.icon;
                      return (
                        <div key={event.id} className="flex gap-4">
                          <div className="flex flex-col items-center">
                            <div className={`flex h-10 w-10 items-center justify-center rounded-full border ${meta.tone}`}>
                              <EventIcon className="h-4 w-4" />
                            </div>
                            {index < events.length - 1 && <div className="mt-2 h-full w-px bg-zinc-800" />}
                          </div>
                          <div className="pb-2">
                            <p className="text-sm font-black text-zinc-100">{meta.label}</p>
                            <p className="mt-1 text-xs font-bold uppercase tracking-[0.18em] text-zinc-400">{formatDate(event.createdAt)}</p>
                            {event.note && <p className="mt-2 text-sm leading-6 text-zinc-400">{event.note}</p>}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </CardContent>
              </Card>
            )}
          </div>

          <div className="space-y-8 xl:sticky xl:top-8 xl:self-start">
            <Card className="rounded-[2.25rem] border-zinc-700/50 bg-[#111113] shadow-sm">
              <CardContent className="p-6 lg:p-8">
                <div className="flex items-center justify-between gap-3">
                  <div>
                    <p className="text-xs font-black uppercase tracking-[0.22em] text-zinc-400">─Éiß╗üu chß╗ënh ─æ╞ín h├áng</p>
                    <h2 className="mt-2 text-2xl font-black tracking-tight text-zinc-100">Cß║¡p nhß║¡t trß║íng th├íi</h2>
                  </div>
                  <div className={`rounded-full border px-4 py-2 text-sm font-black ${selectedStatus.tone}`}>{selectedStatus.label}</div>
                </div>

                <div className="mt-6 grid gap-3 sm:grid-cols-2">
                  {STATUS_OPTIONS.map((option) => {
                    const OptionIcon = option.icon;
                    const active = option.value === status;
                    return (
                      <button key={option.value} type="button" onClick={() => setStatus(option.value)} className={`rounded-[1.35rem] border p-4 text-left transition ${active ? option.tone : "border-zinc-700/50 bg-zinc-900/50 text-zinc-400 hover:border-zinc-600"}`}>
                        <div className="flex items-center gap-3">
                          <div className={`flex h-10 w-10 items-center justify-center rounded-full ${active ? "bg-zinc-700/70" : "bg-zinc-800"}`}>
                            <OptionIcon className="h-4 w-4" />
                          </div>
                          <div>
                            <p className="text-sm font-black">{option.label}</p>
                            <p className="text-xs font-bold uppercase tracking-[0.18em] opacity-70">{option.desc}</p>
                          </div>
                        </div>
                      </button>
                    );
                  })}
                </div>

                <div className="mt-6 grid gap-4">
                  <div>
                    <label className="text-xs font-black uppercase tracking-[0.22em] text-zinc-400">M├ú vß║¡n ─æ╞ín</label>
                    <input value={trackingCode} onChange={(event) => setTrackingCode(event.target.value)} placeholder="UPS123456789" className="mt-2 h-12 w-full rounded-2xl border border-zinc-700/50 bg-zinc-900/50 px-4 text-sm font-medium text-zinc-300 outline-none transition focus:border-primary" />
                  </div>
                  <div>
                    <label className="text-xs font-black uppercase tracking-[0.22em] text-zinc-400">─É╞ín vß╗ï vß║¡n chuyß╗ân</label>
                    <input value={carrier} onChange={(event) => setCarrier(event.target.value)} placeholder="UPS, FedEx, USPS..." className="mt-2 h-12 w-full rounded-2xl border border-zinc-700/50 bg-zinc-900/50 px-4 text-sm font-medium text-zinc-300 outline-none transition focus:border-primary" />
                  </div>
                  <div>
                    <label className="text-xs font-black uppercase tracking-[0.22em] text-zinc-400">Ghi ch├║ nß╗Öi bß╗Ö</label>
                    <textarea value={notes} onChange={(event) => setNotes(event.target.value)} placeholder="Them ghi chu cho doi van hanh, giao nhan hoac ho tro khach hang..." className="mt-2 min-h-[150px] w-full rounded-[1.5rem] border border-zinc-700/50 bg-zinc-900/50 px-4 py-4 text-sm leading-6 text-zinc-300 outline-none transition focus:border-primary" />
                  </div>
                </div>

                <Button size="xl" className="mt-6 w-full justify-between" onClick={handleSave} disabled={isSaving}>
                  <span className="inline-flex items-center gap-2">
                    <Save className="h-4 w-4" />
                    L╞░u cß║¡p nhß║¡t
                  </span>
                  {isSaving ? <Loader2 className="h-4 w-4 animate-spin" /> : null}
                </Button>
              </CardContent>
            </Card>

            <Card className="rounded-[2.25rem] border-zinc-700/50 bg-[#111113] shadow-sm">
              <CardContent className="p-6 lg:p-8">
                <h2 className="text-2xl font-black tracking-tight text-zinc-100">Thanh to├ín & Tß╗òng tiß╗ün</h2>
                <div className="mt-6 space-y-4 text-sm text-zinc-400">
                  <SummaryRow label="Tß║ím t├¡nh" value={formatPrice(order.subtotal || 0)} />
                  <SummaryRow label="Ph├¡ vß║¡n chuyß╗ân" value={formatPrice(order.shippingFee || 0)} />
                  <SummaryRow label="Giß║úm gi├í" value={`-${formatPrice(order.discount || 0)}`} />
                  {order.couponCode && <SummaryRow label="M├ú giß║úm gi├í" value={order.couponCode} />}
                  <SummaryRow label="Ph╞░╞íng thß╗⌐c thanh to├ín" value={paymentLabel(order.paymentMethod)} />
                  <SummaryRow label="Trß║íng th├íi thanh to├ín" value={order.paymentStatus || "Chß╗¥ xß╗¡ l├╜"} />
                  <div className="border-t border-dashed border-zinc-700/50 pt-4">
                    <SummaryRow label="Tß╗òng ─æ╞ín h├áng" value={formatPrice(order.total)} strong />
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card className="rounded-[2.25rem] border-zinc-700/50 bg-[#111113] shadow-sm">
              <CardContent className="p-6 lg:p-8">
                <div className="flex items-center gap-3">
                  <CreditCard className="h-5 w-5 text-primary" />
                  <h2 className="text-2xl font-black tracking-tight text-zinc-100">T├│m tß║»t vß║¡n h├ánh</h2>
                </div>
                <div className="mt-6 grid gap-4">
                  <div className="rounded-[1.5rem] border border-zinc-700/50 bg-zinc-900/50 p-4">
                    <p className="text-[11px] font-black uppercase tracking-[0.22em] text-zinc-400">Li├¬n hß╗ç</p>
                    <p className="mt-2 text-sm font-bold text-zinc-100">{order.user?.email || "Kh├ích"}</p>
                    <p className="mt-1 text-sm text-zinc-400">{order.user?.phone || order.shippingPhone || "Kh├┤ng c├│ S─ÉT"}</p>
                  </div>
                  <div className="rounded-[1.5rem] border border-zinc-700/50 bg-zinc-900/50 p-4">
                    <p className="text-[11px] font-black uppercase tracking-[0.22em] text-zinc-400">Trß║íng th├íi vß║¡n ─æ╞ín</p>
                    <p className="mt-2 text-sm font-bold text-zinc-100">{trackingCode ? "Tracking code ─æ├ú sß║╡n s├áng" : "Cß║ºn th├¬m tracking code khi giao h├áng"}</p>
                    <p className="mt-1 text-sm text-zinc-400">{carrier ? `Carrier: ${carrier}` : "Carrier ch╞░a ─æ╞░ß╗úc g├ín"}</p>
                  </div>
                  <div className="rounded-[1.5rem] border border-zinc-700/50 bg-zinc-900/50 p-4">
                    <p className="text-[11px] font-black uppercase tracking-[0.22em] text-zinc-400">Mß╗æc giao h├áng</p>
                    <p className="mt-2 text-sm font-bold text-zinc-100">{order.deliveredAt ? `Delivered ${formatDate(order.deliveredAt)}` : "Ch╞░a ghi nhß║¡n mß╗æc giao th├ánh c├┤ng"}</p>
                    <p className="mt-1 text-sm text-zinc-400">{order.shippedAt ? `Shipped ${formatDate(order.shippedAt)}` : "Ch╞░a ghi nhß║¡n mß╗æc giao vß║¡n chuyß╗ân"}</p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    </div>
  );
}

function SummaryRow({ label, value, strong = false }: { label: string; value: string; strong?: boolean }) {
  return (
    <div className="flex items-center justify-between gap-3">
      <span className={strong ? "text-base font-black text-zinc-100" : "font-medium text-zinc-500"}>{label}</span>
      <span className={strong ? "text-xl font-black text-zinc-100" : "font-black text-zinc-100"}>{value}</span>
    </div>
  );
}

"use client";

/**
 * LIKEFOOD - Premium Orders Management Module
 * Phase 2: Enhanced Operations UX
 */

import { useCallback, useEffect, useState } from "react";
import { 
  CalendarDays, 
  ChevronDown, 
  ClipboardList, 
  Download, 
  Eye, 
  Loader2, 
  MoreHorizontal, 
  RefreshCw, 
  Search,
  X,
  Package,
  Truck,
  CreditCard,
  User,
  MapPin,
  Clock,
  CheckCircle,
  XCircle,
  AlertCircle
} from "lucide-react";
import { toast } from "sonner";
import { formatPrice } from "@/lib/currency";

interface Order {
  id: number;
  userId: number;
  total: number;
  status: string;
  createdAt: string;
  userEmail?: string;
  userName?: string;
  userPhone?: string;
  itemCount?: number;
  shippingAddress?: string;
  paymentMethod?: string;
}

interface OrderDetail extends Order {
  items?: Array<{
    id: number;
    name: string;
    price: number;
    quantity: number;
    image?: string;
  }>;
  shipping?: {
    carrier?: string;
    trackingNumber?: string;
    estimatedDelivery?: string;
  };
}

const STATUS_CONFIG = [
  { key: 'ALL', label: 'All', color: 'bg-zinc-500/10 text-zinc-400' },
  { key: 'PENDING', label: 'Pending', color: 'bg-amber-500/10 text-amber-400' },
  { key: 'CONFIRMED', label: 'Confirmed', color: 'bg-blue-500/10 text-blue-400' },
  { key: 'PROCESSING', label: 'Processing', color: 'bg-purple-500/10 text-purple-400' },
  { key: 'SHIPPING', label: 'Shipping', color: 'bg-cyan-500/10 text-cyan-400' },
  { key: 'DELIVERED', label: 'Delivered', color: 'bg-emerald-500/10 text-emerald-400' },
  { key: 'COMPLETED', label: 'Completed', color: 'bg-teal-500/10 text-teal-400' },
  { key: 'CANCELLED', label: 'Cancelled', color: 'bg-red-500/10 text-red-400' },
];

const NEXT_ACTIONS: Record<string, string[]> = {
  PENDING: ['CONFIRMED', 'CANCELLED'],
  CONFIRMED: ['PROCESSING', 'CANCELLED'],
  PROCESSING: ['SHIPPING', 'CANCELLED'],
  SHIPPING: ['DELIVERED'],
  DELIVERED: ['COMPLETED'],
};

const PAGE_SIZE = 15;

const getStatusConfig = (statusKey: string) => {
  return STATUS_CONFIG.find(s => s.key === statusKey) || STATUS_CONFIG[0];
};

export default function AdminOrdersPage() {
  const [orders, setOrders] = useState<Order[]>([]);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [status, setStatus] = useState('ALL');
  const [search, setSearch] = useState('');
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [updatingId, setUpdatingId] = useState<number | null>(null);
  
  // Selection & Drawer
  const [selectedOrders, setSelectedOrders] = useState<Set<number>>(new Set());
  const [bulkStatus, setBulkStatus] = useState('');
  const [selectedOrder, setSelectedOrder] = useState<OrderDetail | null>(null);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [detailLoading, setDetailLoading] = useState(false);

  const debouncedSearch = search;

  const loadOrders = useCallback(async () => {
    setIsLoading(true);
    try {
      const params = new URLSearchParams({ 
        page: page.toString(), 
        limit: PAGE_SIZE.toString() 
      });
      if (status !== 'ALL') params.set('status', status);
      if (debouncedSearch) params.set('search', debouncedSearch);
      if (dateFrom) params.set('dateFrom', dateFrom);
      if (dateTo) params.set('dateTo', dateTo);
      
      const response = await fetch(`/api/orders?${params.toString()}`);
      const data = await response.json().catch(() => ({}));
      if (!response.ok) throw new Error(data?.error || 'Failed to load orders');
      
      setOrders(Array.isArray(data.orders) ? data.orders : []);
      setTotal(data.pagination?.total || data.total || 0);
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to load orders');
    } finally {
      setIsLoading(false);
    }
  }, [page, status, debouncedSearch, dateFrom, dateTo]);

  useEffect(() => {
    void loadOrders();
  }, [loadOrders]);

  useEffect(() => {
    setPage(1);
  }, [status, debouncedSearch, dateFrom, dateTo]);

  const updateStatus = async (orderId: number, nextStatus: string) => {
    setUpdatingId(orderId);
    try {
      const response = await fetch(`/api/admin/orders/${orderId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: nextStatus }),
      });
      const data = await response.json().catch(() => ({}));
      if (!response.ok) throw new Error(data?.error || 'Failed to update status');
      
      toast.success(`Order #${String(orderId).slice(-6)} ΓåÆ ${nextStatus}`);
      await loadOrders();
      if (selectedOrder?.id === orderId) {
        loadOrderDetail(orderId);
      }
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to update status');
    } finally {
      setUpdatingId(null);
    }
  };

  const applyBulkStatus = async () => {
    if (!bulkStatus || selectedOrders.size === 0) return;
    const ids = Array.from(selectedOrders);
    try {
      await Promise.all(ids.map(id => updateStatus(id, bulkStatus)));
      setSelectedOrders(new Set());
      setBulkStatus('');
    } catch {
      toast.error('Some orders failed to update');
    }
  };

  const loadOrderDetail = async (orderId: number) => {
    setDetailLoading(true);
    try {
      const response = await fetch(`/api/orders/${orderId}`);
      const data = await response.json().catch(() => ({}));
      if (response.ok) {
        setSelectedOrder(data);
      }
    } catch (error) {
      console.error('Failed to load order detail:', error);
    } finally {
      setDetailLoading(false);
    }
  };

  const openDrawer = (order: Order) => {
    setSelectedOrder(null);
    setDrawerOpen(true);
    loadOrderDetail(order.id);
  };

  const closeDrawer = () => {
    setDrawerOpen(false);
    setSelectedOrder(null);
  };

  // Selection handlers
  const toggleSelectAll = () => {
    if (selectedOrders.size === orders.length) {
      setSelectedOrders(new Set());
    } else {
      setSelectedOrders(new Set(orders.map(o => o.id)));
    }
  };

  const toggleSelect = (orderId: number) => {
    const newSelected = new Set(selectedOrders);
    if (newSelected.has(orderId)) {
      newSelected.delete(orderId);
    } else {
      newSelected.add(orderId);
    }
    setSelectedOrders(newSelected);
  };

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-semibold text-zinc-100">Orders</h1>
          <p className="text-sm text-zinc-500 mt-0.5">Manage and track all orders</p>
        </div>
        <div className="flex items-center gap-2">
          <a 
            href="/api/admin/export?type=orders" 
            download
            className="px-3.5 py-2 rounded-md border border-zinc-700 bg-zinc-900 text-sm font-medium text-zinc-300 hover:bg-zinc-800 transition-colors flex items-center gap-2"
          >
            <Download className="h-4 w-4" />
            Export
          </a>
          <button 
            onClick={() => void loadOrders()}
            disabled={isLoading}
            className="px-3.5 py-2 rounded-md border border-zinc-700 bg-zinc-900 text-sm font-medium text-zinc-300 hover:bg-zinc-800 transition-colors flex items-center gap-2"
          >
            <RefreshCw className={`h-4 w-4 ${isLoading ? 'animate-spin' : ''}`} />
            Refresh
          </button>
        </div>
      </div>

      {/* Filter Bar */}
      <div className="rounded-lg border border-zinc-700/50 bg-[#111113] p-3">
        <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
          {/* Search */}
          <div className="relative flex-1 max-w-md">
            <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-zinc-500" />
            <input
              type="text"
              placeholder="Search order ID, phone, email..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="h-9 w-full rounded-md border border-zinc-700 bg-zinc-900 pl-9 pr-8 text-sm text-zinc-100 placeholder:text-zinc-500 focus:border-teal-500 focus:outline-none"
            />
            {search && (
              <button onClick={() => setSearch('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-zinc-500 hover:text-zinc-300">
                <X className="h-4 w-4" />
              </button>
            )}
          </div>

          {/* Date Range */}
          <div className="flex items-center gap-2">
            <CalendarDays className="h-4 w-4 text-zinc-500" />
            <input 
              type="date" 
              value={dateFrom} 
              onChange={(e) => setDateFrom(e.target.value)}
              className="h-9 rounded-md border border-zinc-700 bg-zinc-900 px-3 text-sm text-zinc-100 focus:border-teal-500 focus:outline-none"
            />
            <span className="text-zinc-500">to</span>
            <input 
              type="date" 
              value={dateTo} 
              onChange={(e) => setDateTo(e.target.value)}
              className="h-9 rounded-md border border-zinc-700 bg-zinc-900 px-3 text-sm text-zinc-100 focus:border-teal-500 focus:outline-none"
            />
          </div>
        </div>
      </div>

      {/* Status Tabs */}
      <div className="flex flex-wrap gap-2">
        {STATUS_CONFIG.map((config) => (
          <button
            key={config.key}
            onClick={() => setStatus(config.key)}
            className={`px-3.5 py-2 rounded-full text-xs font-semibold uppercase tracking-wide transition-colors ${
              status === config.key
                ? 'bg-teal-600 text-white'
                : 'border border-zinc-700 bg-zinc-900/50 text-zinc-400 hover:border-zinc-600 hover:text-zinc-200'
            }`}
          >
            {config.label}
          </button>
        ))}
      </div>

      {/* Bulk Actions Bar */}
      {selectedOrders.size > 0 && (
        <div className="rounded-lg border border-teal-500/30 bg-teal-500/5 px-4 py-2.5 flex items-center justify-between">
          <span className="text-sm font-medium text-teal-400">
            {selectedOrders.size} selected
          </span>
          <div className="flex items-center gap-2">
            <select 
              value={bulkStatus}
              onChange={(e) => setBulkStatus(e.target.value)}
              className="h-8 rounded-md border border-zinc-700 bg-zinc-900 px-2 text-xs text-zinc-100"
            >
              <option value="">Update Status</option>
              {['CONFIRMED','PROCESSING','SHIPPING','DELIVERED','COMPLETED','CANCELLED'].map(s => (
                <option key={s} value={s}>ΓåÆ {s}</option>
              ))}
            </select>
            <button 
              onClick={() => void applyBulkStatus()}
              disabled={!bulkStatus}
              className="h-8 px-3 rounded-md border border-teal-600/50 bg-teal-600/20 text-xs text-teal-300 hover:bg-teal-600/30 disabled:opacity-40 disabled:cursor-not-allowed"
            >
              Apply
            </button>
            <button className="h-8 px-3 rounded-md border border-zinc-700 bg-zinc-900 text-xs text-zinc-300 hover:bg-zinc-800">
              Export Selected
            </button>
          </div>
        </div>
      )}

      {/* Table */}
      <div className="rounded-lg border border-zinc-700/50 bg-[#111113] overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-zinc-700/50 bg-zinc-900/50">
                <th className="w-10 px-4 py-3">
                  <input 
                    type="checkbox" 
                    checked={selectedOrders.size === orders.length && orders.length > 0}
                    onChange={toggleSelectAll}
                    className="rounded border-zinc-600 bg-zinc-800 text-teal-500"
                  />
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold uppercase tracking-wider text-zinc-500">Order</th>
                <th className="px-4 py-3 text-left text-xs font-semibold uppercase tracking-wider text-zinc-500">Customer</th>
