// POST /api/auth/magic-link ΓÇö Gß╗¡i Magic Link ─æ─âng nhß║¡p
export async function POST(req: NextRequest) {
    try {
        const { email, turnstileToken } = await req.json();

        if (!email || typeof email !== "string") {
            return NextResponse.json({ error: "Email kh├┤ng hß╗úp lß╗ç" }, { status: 400 });
        }

        // T├¡ch hß╗úp chß╗æng Bruteforce/Spam Rate Limiting cho ri├¬ng Magic Link/OTP
        const identifier = getRateLimitIdentifier(req);
        const rateResult = await applyRateLimit(identifier, loginRateLimit);
        if (!rateResult.success && rateResult.error) {
            return rateResult.error;
        }

        const captcha = await verifyTurnstileToken({ req, token: turnstileToken, action: "auth_magic_link" });
        if (!captcha.ok) {
            return NextResponse.json({ error: captcha.message }, { status: 400 });
        }

        const user = await prisma.user.findUnique({
            where: { email: email.toLowerCase() },
            select: { id: true, email: true, emailVerified: true },
        });

        // Anti-enumeration: lu├┤n trß║ú vß╗ü th├ánh c├┤ng
        if (!user || !user.emailVerified) {
            return NextResponse.json({ message: "Nß║┐u email tß╗ôn tß║íi, link ─æ─âng nhß║¡p ─æ├ú ─æ╞░ß╗úc gß╗¡i." });
        }

        // Tß║ío token an to├án
        const token = crypto.randomBytes(32).toString("hex");
        const expires = new Date(Date.now() + 15 * 60 * 1000); // 15 ph├║t

        // X├│a old tokens, l╞░u mß╗¢i v├áo verificationtoken
        await prisma.verificationtoken.deleteMany({
            where: { identifier: `magic:${user.id}` },
        });
        await prisma.verificationtoken.create({
            data: {
                identifier: `magic:${user.id}`,
                token: token,
                expires,
            },
        });

        const magicUrl = `${process.env.NEXTAUTH_URL}/api/auth/magic-link/confirm?token=${token}&email=${encodeURIComponent(email)}`;

        const emailResult = await sendVerificationEmail(email, token, "MAGIC_LINK", magicUrl);

        if (!emailResult.success) {
            logger.error(`[magic-link] Failed to send email: ${emailResult.error}`);
            return NextResponse.json(
                { error: "Kh├┤ng thß╗â gß╗¡i email. Vui l├▓ng kiß╗âm tra cß║Ñu h├¼nh SMTP." },
                { status: 500 }
            );
        }

        return NextResponse.json({ message: "Link ─æ─âng nhß║¡p ─æ├ú ─æ╞░ß╗úc gß╗¡i v├áo email cß╗ºa bß║ín." });
    } catch (error) {
        const message = error instanceof Error ? error.message : String(error);
        logger.error("[magic-link] Error", error as Error, { context: "auth-magic-link" });
        return NextResponse.json(
            { error: "Lß╗ùi server. Kiß╗âm tra cß║Ñu h├¼nh SMTP v├á env." },
