const EMAIL_TEMPLATES: Record<EmailType, { subject: { vi: string; en: string }; templateKey: string }> = {
  welcome: {
    subject: { vi: "Ch├áo mß╗½ng ─æß║┐n vß╗¢i LIKEFOOD!", en: "Welcome to LIKEFOOD!" },
    templateKey: "welcome_email",
  },
