    templateKey: "abandoned_cart",
  },
  order_confirmation: {
    subject: { vi: "X├íc nhß║¡n ─æ╞ín h├áng #ORDER_ID", en: "Order Confirmation #ORDER_ID" },
    templateKey: "order_confirmation",
  },
  shipping_notification: {
    subject: { vi: "─É╞ín h├áng cß╗ºa bß║ín ─æang ─æ╞░ß╗úc giao!", en: "Your order is on the way!" },
    templateKey: "shipping_notification",
