  email: {
    orderUpdates: boolean;
    promotions: boolean;
    flashSales: boolean;
    newsletters: boolean;
    recommendations: boolean;
  };
  push: {
    enabled: boolean;
    orderUpdates: boolean;
    flashSales: boolean;
    priceDrops: boolean;
    restocks: boolean;
  };
  sms: {
    enabled: boolean;
    orderUpdates: boolean;
    promotions: boolean;
  };
  marketing: boolean;
}

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session?.user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { searchParams } = new URL(req.url);
    const userId = searchParams.get("userId");

    if (!userId) {
      return NextResponse.json(
        { error: "Missing required parameter: userId" },
        { status: 400 }
      );
    }

    if (String(session.user.id) !== String(userId) && session.user.role !== "ADMIN") {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    // Try to get existing preferences
    const preferences = await prisma.user.findUnique({
      where: { id: Number(userId)},
      select: { notificationPreferences: true },
    });

    // If not exists, return defaults
    if (!preferences?.notificationPreferences) {
      const defaults: NotificationPreferences = {
        userId: Number(userId),
        email: {
          orderUpdates: true,
          promotions: true,
          flashSales: true,
          newsletters: false,
          recommendations: true,
        },
        push: {
          enabled: true,
          orderUpdates: true,
          flashSales: true,
          priceDrops: true,
          restocks: false,
        },
        sms: {
          enabled: false,
          orderUpdates: true,
          promotions: false,
        },
        marketing: true,
      };

      return NextResponse.json({
        success: true,
        preferences: defaults,
      });
    }

    return NextResponse.json({
      success: true,
      preferences: preferences.notificationPreferences,
    });
  } catch (error) {
    logger.error("Error fetching preferences", error as Error, { context: "notify-preferences-api" });
    return NextResponse.json(
      { error: "Failed to fetch preferences" },
      { status: 500 }
    );
  }
}

export async function POST(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session?.user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const body = await req.json();
    const { userId, preferences } = body as { userId: number; preferences: NotificationPreferences };

    if (!userId || !preferences) {
      return NextResponse.json(
        { error: "Missing required fields: userId, preferences" },
