    selectedIds,
    onToggleSelect,
    onToggleAll,
    allSelected,
    someSelected,
    onRemoveItem,
    onUpdateQuantity,
    onRemoveSelected,
    onSaveForLater,
}: CartItemListProps) {
  const { t } = useLanguage();
