import { useEffect, useState, useCallback } from "react";
import confetti from "canvas-confetti";
import { toast } from "sonner";

interface OrderSuccessProps {
    language: string;
    t: (key: string) => string;
    orderId: string | null;
    paymentMethod: PaymentMethod;
    finalTotal: number;
}

export default function OrderSuccess({
    language, t, orderId, paymentMethod, finalTotal,
}: OrderSuccessProps) {
    const vi = language === "vi";
    const [isRedirecting, setIsRedirecting] = useState(false);

    // Celebrate!
    useEffect(() => {
        const duration = 3 * 1000;
        const animationEnd = Date.now() + duration;
        const defaults = { startVelocity: 30, spread: 360, ticks: 60, zIndex: 0 };

        const randomInRange = (min: number, max: number) => Math.random() * (max - min) + min;

        const interval = setInterval(function() {
            const timeLeft = animationEnd - Date.now();
            if (timeLeft <= 0) return clearInterval(interval);

            const particleCount = 50 * (timeLeft / duration);
            confetti({ ...defaults, particleCount, origin: { x: randomInRange(0.1, 0.3), y: Math.random() - 0.2 } });
            confetti({ ...defaults, particleCount, origin: { x: randomInRange(0.7, 0.9), y: Math.random() - 0.2 } });
        }, 250);

        return () => clearInterval(interval);
    }, []);

    // Handle Stripe payment redirect
    const handleStripePayment = useCallback(async () => {
        if (!orderId || isRedirecting) return;
        setIsRedirecting(true);

        try {
            const res = await fetch("/api/checkout/create-session", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ orderId }),
            });

            if (!res.ok) {
                const err = await res.json().catch(() => ({}));
                throw new Error(err.error || "Stripe session creation failed");
            }

            const data = await res.json();

            if (data.url) {
                window.location.href = data.url;
            } else {
                throw new Error(vi ? "Kh├┤ng nhß║¡n ─æ╞░ß╗úc URL thanh to├ín" : "No checkout URL received");
            }
        } catch (error) {
            const msg = error instanceof Error ? error.message : "Unknown error";
            toast.error(msg);
            setIsRedirecting(false);
        }
