                                        <Heart className="w-4 h-4 mr-2" /> <span className="hidden xs:inline">{t('shop.addToWishlist')}</span>
                                    </Button>
                                </div>
                            </div>

                            {/* Right: Info */}
                            <div className="p-10 lg:p-16 flex flex-col justify-center">
