import { useState, useEffect } from "react";
import { signOut } from "next-auth/react";
import { motion, AnimatePresence } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Lock, Shield, Clock, Monitor, AlertTriangle, Trash2, Eye, EyeOff, Save, Loader2, Link2, Unlink } from "lucide-react";
import { useLanguage } from "@/lib/i18n/context";
import { toast } from "sonner";

interface SecuritySectionProps {
    session: {
        user: {
            id?: number;
            email?: string | null;
            name?: string | null;
            role?: string;
        };
    };
}

export function SecuritySection({ session }: SecuritySectionProps) {
    const { language, t, isVietnamese } = useLanguage();

    const profileT = (_key: string, fallback: string) => {
        return fallback;
    };

    // --- Change Password state ---
    const [pwData, setPwData] = useState({ current: "", newPw: "", confirm: "" });
    const [showPw, setShowPw] = useState({ current: false, new: false, confirm: false });
    const [pwLoading, setPwLoading] = useState(false);
    const [pwError, setPwError] = useState("");

    // --- Login History state ---
    const [loginHistory, setLoginHistory] = useState<Array<{
        id: number;
        ipAddress?: string | null;
        userAgent?: string | null;
        country?: string | null;
        isSuspicious: boolean;
        createdAt: string;
    }>>([]);
    const [historyLoading, setHistoryLoading] = useState(false);
    const [historyLoaded, setHistoryLoaded] = useState(false);

    // --- Delete Account state ---
    const [showDeleteModal, setShowDeleteModal] = useState(false);
    const [deletePassword, setDeletePassword] = useState("");
    const [deleteLoading, setDeleteLoading] = useState(false);
    const [deleteConfirmed, setDeleteConfirmed] = useState(false);

    // --- 2FA state ---
    const [twoFAEnabled, setTwoFAEnabled] = useState(false);
    const [twoFALoading, setTwoFALoading] = useState(false);
    const [twoFALoaded, setTwoFALoaded] = useState(false);

    // --- Google Connection state ---
    const [googleConnected, setGoogleConnected] = useState(false);
    const [googleLoading, setGoogleLoading] = useState(false);
    const [googleLoaded, setGoogleLoaded] = useState(false);

    // --- 2FA Modal state ---
    const [show2FAModal, setShow2FAModal] = useState(false);
    const [otp2FA, setOtp2FA] = useState("");
    const [otpLoading, setOtpLoading] = useState(false);

    const fetchTwoFAStatus = async () => {
        if (twoFALoaded) return;
        try {
            const res = await fetch("/api/auth/2fa/toggle");
            if (res.ok) {
                const d = await res.json();
                setTwoFAEnabled(d.twoFactorEnabled);
                setTwoFALoaded(true);
            }
        } catch { /* ignore */ }
    };

    const fetchGoogleStatus = async () => {
        if (googleLoaded) return;
        try {
            const res = await fetch("/api/auth/google/link");
            if (res.ok) {
                const d = await res.json();
                setGoogleConnected(d.isConnected);
                setGoogleLoaded(true);
            }
        } catch { /* ignore */ }
    };

    useEffect(() => {
        fetchTwoFAStatus();
        fetchGoogleStatus();
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    const handleToggle2FA = async (enable: boolean) => {
        if (enable) {
            // Initiate 2FA Enable Process: Send Email
            setTwoFALoading(true);
            try {
                const res = await fetch("/api/auth/2fa/send", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ email: session.user.email }),
                });
                if (res.ok) {
                    setShow2FAModal(true);
                    setOtp2FA("");
                } else {
                    toast.error(profileT('profile.failedToSendCode', isVietnamese ? 'Kh├┤ng thß╗â gß╗¡i m├ú x├íc nhß║¡n' : 'Failed to send confirmation code'));
                }
            } catch {
                toast.error(profileT('profile.connectionError', isVietnamese ? 'Lß╗ùi kß║┐t nß╗æi' : 'Connection error'));
            } finally {
                setTwoFALoading(false);
            }
        } else {
            // Disable process
            setTwoFALoading(true);
            try {
                const res = await fetch("/api/auth/2fa/toggle", {
                    method: "PATCH",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ enabled: false }),
                });
                const data = await res.json();
                if (res.ok) {
                    setTwoFAEnabled(false);
                    toast.success(profileT('profile.twoFactorDisabled', isVietnamese ? '─É├ú tß║»t x├íc thß╗▒c 2 lß╗¢p' : 'Two-factor authentication disabled'));
                } else {
                    toast.error(data.error || profileT('profile.unableToDisable2FA', isVietnamese ? 'Kh├┤ng thß╗â tß║»t 2FA' : 'Unable to disable 2FA'));
                }
            } catch {
                toast.error(profileT('profile.connectionError', isVietnamese ? 'Lß╗ùi kß║┐t nß╗æi' : 'Connection error'));
            } finally {
                setTwoFALoading(false);
            }
        }
    };

    const handleConfirm2FA = async () => {
        if (otp2FA.length < 6) return;
        setOtpLoading(true);
        try {
            const res = await fetch("/api/auth/2fa/toggle", {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ enabled: true, otp: otp2FA }),
            });
            const data = await res.json();
            if (res.ok) {
                setTwoFAEnabled(true);
                setShow2FAModal(false);
                toast.success(profileT('profile.twoFactorEnabledSuccess', isVietnamese ? '─É├ú bß║¡t x├íc thß╗▒c 2 lß╗¢p th├ánh c├┤ng' : 'Two-factor authentication enabled successfully'));
            } else {
                    toast.error(data.error || profileT('profile.invalidConfirmationCode', isVietnamese ? 'M├ú x├íc nhß║¡n kh├┤ng hß╗úp lß╗ç' : 'Invalid confirmation code'));
            }
        } catch {
            toast.error(profileT('profile.connectionError', isVietnamese ? 'Lß╗ùi kß║┐t nß╗æi' : 'Connection error'));
        } finally {
            setOtpLoading(false);
        }
    };

    const passwordStrength = (pw: string) => {
        let score = 0;
        if (pw.length >= 8) score++;
        if (/[A-Z]/.test(pw)) score++;
        if (/[0-9]/.test(pw)) score++;
        if (/[^A-Za-z0-9]/.test(pw)) score++;
        return score;
    };

    const strengthLabel = isVietnamese ? ["", "Yß║┐u", "Trung b├¼nh", "Tß╗æt", "Mß║ính"] : ["", "Weak", "Medium", "Good", "Strong"];
    const strengthColor = ["", "bg-red-400", "bg-orange-400", "bg-yellow-400", "bg-green-500"];
    const pwStrength = passwordStrength(pwData.newPw);

    const handleChangePassword = async (e: React.FormEvent) => {
        e.preventDefault();
        if (pwData.newPw !== pwData.confirm) {
            setPwError(profileT('profile.passwordMismatch', isVietnamese ? 'Mß║¡t khß║⌐u x├íc nhß║¡n kh├┤ng khß╗¢p' : 'Password confirmation does not match'));
            return;
        }
        setPwLoading(true);
        setPwError("");
        try {
            const res = await fetch("/api/auth/change-password", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ currentPassword: pwData.current, newPassword: pwData.newPw, confirmPassword: pwData.confirm }),
            });
            const data = await res.json();
            if (res.ok) {
                toast.success(profileT('profile.passwordChangedSuccess', isVietnamese ? '─Éß╗òi mß║¡t khß║⌐u th├ánh c├┤ng' : 'Password changed successfully'));
                setPwData({ current: "", newPw: "", confirm: "" });
            } else {
                setPwError(data.error || profileT('profile.passwordChangeFailed', isVietnamese ? '─Éß╗òi mß║¡t khß║⌐u thß║Ñt bß║íi' : 'Failed to change password'));
            }
        } catch {
            setPwError(profileT('profile.connectionError', isVietnamese ? 'Lß╗ùi kß║┐t nß╗æi' : 'Connection error'));
        } finally {
            setPwLoading(false);
        }
    };

    const fetchLoginHistory = async () => {
        if (historyLoaded) return;
        setHistoryLoading(true);
        try {
            const res = await fetch("/api/auth/login-history");
            if (res.ok) {
                const data = await res.json();
                setLoginHistory(data.history || []);
                setHistoryLoaded(true);
            }
        } catch { /* ignore */ }
        finally { setHistoryLoading(false); }
    };

    const handleConnectGoogle = async () => {
        // Redirect to login page with Google, user will be redirected back after connecting
        // For now, show a message to use the login page
        setGoogleLoading(true);
        try {
            const res = await fetch("/api/auth/google/link", { method: "POST" });
            if (res.ok) {
                toast.success(profileT('profile.googleLinkInitiated', isVietnamese ? 'Vui l├▓ng ─æ─âng nhß║¡p bß║▒ng Google ─æß╗â kß║┐t nß╗æi t├ái khoß║ún' : 'Please sign in with Google to link your account'));
                // In a real implementation, we would redirect to the OAuth provider
                // For now, we just refresh the status after a delay
                setTimeout(() => {
                    fetchGoogleStatus();
                    setGoogleLoading(false);
                }, 2000);
            } else {
                const d = await res.json();
                toast.error(d.error || profileT('profile.googleLinkFailed', isVietnamese ? 'Kß║┐t nß╗æi Google thß║Ñt bß║íi' : 'Failed to connect Google'));
                setGoogleLoading(false);
            }
        } catch {
            toast.error(profileT('profile.connectionError', isVietnamese ? 'Lß╗ùi kß║┐t nß╗æi' : 'Connection error'));
            setGoogleLoading(false);
        }
    };

    const handleDisconnectGoogle = async () => {
        setGoogleLoading(true);
        try {
            const res = await fetch("/api/auth/google/link", { method: "DELETE" });
            if (res.ok) {
                setGoogleConnected(false);
                toast.success(profileT('profile.googleDisconnected', isVietnamese ? '─É├ú ngß║»t kß║┐t nß╗æi Google' : 'Google disconnected'));
            } else {
                const d = await res.json();
                toast.error(d.error || profileT('profile.googleUnlinkFailed', isVietnamese ? 'Ngß║»t kß║┐t nß╗æi Google thß║Ñt bß║íi' : 'Failed to disconnect Google'));
            }
        } catch {
            toast.error(profileT('profile.connectionError', isVietnamese ? 'Lß╗ùi kß║┐t nß╗æi' : 'Connection error'));
        } finally {
            setGoogleLoading(false);
        }
    };

    const handleDeleteAccount = async () => {
        if (!deleteConfirmed || !deletePassword) return;
        setDeleteLoading(true);
        try {
            const res = await fetch("/api/user/account", {
                method: "DELETE",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ password: deletePassword }),
            });
            if (res.ok) {
                toast.success(profileT('profile.deleteAccountSuccess', isVietnamese ? 'X├│a t├ái khoß║ún th├ánh c├┤ng' : 'Account deleted successfully'));
                await signOut({ callbackUrl: "/" });
            } else {
                const d = await res.json();
                toast.error(d.error || profileT('profile.deleteAccountFailed', isVietnamese ? 'X├│a t├ái khoß║ún thß║Ñt bß║íi' : 'Failed to delete account'));
            }
        } catch {
            toast.error(profileT('profile.connectionError', isVietnamese ? 'Lß╗ùi kß║┐t nß╗æi' : 'Connection error'));
        } finally {
            setDeleteLoading(false);
        }
    };

    const formatDevice = (ua?: string | null) => {
        if (!ua) return profileT('profile.unknownDevice', isVietnamese ? 'Thiß║┐t bß╗ï kh├┤ng x├íc ─æß╗ïnh' : 'Unknown device');
        if (ua.includes("Mobile")) return isVietnamese ? "─Éiß╗çn thoß║íi" : "Mobile";
        if (ua.includes("Tablet")) return isVietnamese ? "M├íy t├¡nh bß║úng" : "Tablet";
        return isVietnamese ? "M├íy t├¡nh" : "Desktop";
    };

    return (
        <>
            {/* Change Password Card */}
            <Card className="border-none shadow-lg shadow-slate-200/50 rounded-[2.5rem]">
                <CardContent className="p-8 md:p-10">
                    <h2 className="text-2xl font-black uppercase tracking-tighter mb-6 flex items-center gap-3">
                        <Lock className="w-6 h-6 text-primary" />
                        {profileT('profile.changePassword', isVietnamese ? '─Éß╗òi mß║¡t khß║⌐u' : 'Change password')}
                    </h2>
                    <form onSubmit={handleChangePassword} className="space-y-4 max-w-md">
                        {pwError && (
                            <div className="p-3 rounded-2xl bg-red-50 border border-red-100 text-red-600 text-sm font-medium flex items-center gap-2">
                                <AlertTriangle className="w-4 h-4 shrink-0" /> {pwError}
                            </div>
                        )}
                        {/* Current password */}
                        <div className="relative">
                            <label className="text-xs font-black uppercase tracking-widest text-slate-400 mb-2 block">
                                {profileT('profile.currentPassword', isVietnamese ? 'Mß║¡t khß║⌐u hiß╗çn tß║íi' : 'Current password')}
                            </label>
                            <div className="relative">
                                <input
                                    type={showPw.current ? "text" : "password"} required
                                    value={pwData.current}
                                    onChange={e => setPwData(p => ({ ...p, current: e.target.value }))}
                                    className="w-full bg-slate-50 border-none ring-1 ring-slate-100 rounded-2xl px-6 pr-12 py-4 outline-none focus:ring-2 focus:ring-primary/20 transition-all font-medium"
                                    placeholder={profileT('profile.enterCurrentPassword', isVietnamese ? 'Nhß║¡p mß║¡t khß║⌐u hiß╗çn tß║íi' : 'Enter current password')}
                                />
                                <button type="button" onClick={() => setShowPw(p => ({ ...p, current: !p.current }))}
                                    className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-600">
                                    {showPw.current ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                </button>
                            </div>
                        </div>
                        {/* New password */}
                        <div>
                            <label className="text-xs font-black uppercase tracking-widest text-slate-400 mb-2 block">
                                {profileT('profile.newPasswordLabel', isVietnamese ? 'Mß║¡t khß║⌐u mß╗¢i' : 'New password')}
                            </label>
                            <div className="relative">
                                <input
                                    type={showPw.new ? "text" : "password"} required
                                    value={pwData.newPw}
                                    onChange={e => setPwData(p => ({ ...p, newPw: e.target.value }))}
                                    className="w-full bg-slate-50 border-none ring-1 ring-slate-100 rounded-2xl px-6 pr-12 py-4 outline-none focus:ring-2 focus:ring-primary/20 transition-all font-medium"
                                    placeholder={profileT('profile.atLeast8Chars', isVietnamese ? '├ìt nhß║Ñt 8 k├╜ tß╗▒' : 'At least 8 characters')}
                                />
                                <button type="button" onClick={() => setShowPw(p => ({ ...p, new: !p.new }))}
                                    className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-600">
                                    {showPw.new ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                </button>
                            </div>
                            {pwData.newPw && (
                                <div className="mt-2 space-y-1">
                                    <div className="flex gap-1">
                                        {[1, 2, 3, 4].map(i => (
                                            <div key={i} className={`flex-1 h-1.5 rounded-full transition-all ${i <= pwStrength ? strengthColor[pwStrength] : "bg-slate-100"}`} />
                                        ))}
                                    </div>
                                    <p className="text-xs text-slate-400 font-medium">{strengthLabel[pwStrength]}</p>
                                </div>
                            )}
                        </div>
                        {/* Confirm password */}
                        <div>
                            <label className="text-xs font-black uppercase tracking-widest text-slate-400 mb-2 block">
                                {profileT('profile.confirmPassword', isVietnamese ? 'X├íc nhß║¡n mß║¡t khß║⌐u' : 'Confirm password')}
                            </label>
                            <div className="relative">
                                <input
                                    type={showPw.confirm ? "text" : "password"} required
                                    value={pwData.confirm}
                                    onChange={e => setPwData(p => ({ ...p, confirm: e.target.value }))}
                                    className={`w-full bg-slate-50 border-none ring-1 rounded-2xl px-6 pr-12 py-4 outline-none focus:ring-2 transition-all font-medium ${pwData.confirm && pwData.newPw !== pwData.confirm ? "ring-red-300 focus:ring-red-200" : "ring-slate-100 focus:ring-primary/20"}`}
                                    placeholder={profileT('profile.reEnterNewPassword', isVietnamese ? 'Nhß║¡p lß║íi mß║¡t khß║⌐u mß╗¢i' : 'Re-enter new password')}
                                />
                                <button type="button" onClick={() => setShowPw(p => ({ ...p, confirm: !p.confirm }))}
                                    className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-600">
                                    {showPw.confirm ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                </button>
                            </div>
                        </div>
                        <Button type="submit" disabled={pwLoading} className="h-12 px-8 rounded-full bg-slate-900 hover:bg-emerald-600 text-white font-bold uppercase tracking-widest transition-all">
                            {pwLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <><Save className="w-4 h-4 mr-2" />{profileT('profile.changePassword', isVietnamese ? '─Éß╗òi mß║¡t khß║⌐u' : 'Change password')}</>}
                        </Button>
                    </form>
                </CardContent>
            </Card>

            {/* 2FA Toggle Card */}
            <Card className="border-none shadow-lg shadow-slate-200/50 rounded-[2.5rem]">
                <CardContent className="p-8 md:p-10">
                    <h2 className="text-2xl font-black uppercase tracking-tighter mb-2 flex items-center gap-3">
                        <Shield className="w-6 h-6 text-primary" />
                        {profileT('profile.twoFactorAuth', isVietnamese ? 'X├íc thß╗▒c hai lß╗¢p (2FA)' : 'Two-factor authentication (2FA)')}
                    </h2>
                    <p className="text-slate-500 font-medium text-sm mb-6">
                        {profileT('profile.twoFactorDescription', isVietnamese ? 'T─âng c╞░ß╗¥ng bß║úo mß║¡t bß║▒ng m├ú x├íc thß╗▒c mß╗ùi khi ─æ─âng nhß║¡p.' : 'Improve security with a verification code on login.')}
                    </p>
                    <div className="flex items-center justify-between p-5 rounded-2xl bg-slate-50 border-2 border-slate-100">
                        <div>
                            <p className="font-black text-slate-900">
                                {twoFAEnabled
                                    ? profileT('profile.twoFactorEnabled', isVietnamese ? '─É├ú bß║¡t 2FA' : '2FA enabled')
                                    : profileT('profile.twoFactorDisabled', isVietnamese ? '─É├ú tß║»t 2FA' : '2FA disabled')}
                            </p>
                            <p className="text-sm text-slate-400 font-medium">
