import { useState, useCallback } from "react";
import Image from "next/image";
import { Star, Upload, X, Loader2, Image as ImageIcon, Check } from "lucide-react";
import { toast } from "sonner";
import { useLanguage } from "@/lib/i18n/context";
import { useSession } from "next-auth/react";

interface ReviewFormProps {
    productId: number;
    orderItemId: string;
    productName: string;
    productImage?: string;
    onSuccess?: () => void;
    onCancel?: () => void;
}

interface MediaItem {
    id: number | string;
    url: string;
    type: "image" | "video";
    isUploading?: boolean;
}

export function ReviewForm({
    productId,
    orderItemId,
    productName,
    productImage,
    onSuccess,
    onCancel
}: ReviewFormProps) {
    const { language } = useLanguage();
    const { data: session, status } = useSession();
    const [rating, setRating] = useState(0);
    const [hoverRating, setHoverRating] = useState(0);
    const [comment, setComment] = useState("");
    const [media, setMedia] = useState<MediaItem[]>([]);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isUploading, setIsUploading] = useState(false);

    // Handle file selection
    const handleFileSelect = useCallback(async (files: FileList | null) => {
        if (!files || files.length === 0) return;

        const MAX_FILES = 5;
        const MAX_SIZE = 10 * 1024 * 1024; // 10MB

        const remainingSlots = MAX_FILES - media.length;
        if (remainingSlots <= 0) {
            toast.error(language === "vi" ? "Chß╗ë ─æ╞░ß╗úc upload tß╗æi ─æa 5 ß║únh/video" : "Maximum 5 images/videos allowed");
            return;
        }

        const filesToUpload = Array.from(files).slice(0, remainingSlots);

        // Validate files
        for (const file of filesToUpload) {
            if (file.size > MAX_SIZE) {
                toast.error(language === "vi" ? `File ${file.name} qu├í lß╗¢n (tß╗æi ─æa 10MB)` : `File ${file.name} is too large (max 10MB)`);
                return;
            }
        }

        setIsUploading(true);

        // Upload files
        for (const file of filesToUpload) {
            const tempId = `temp-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
            const isVideo = file.type.startsWith("video/");

            // Add placeholder
            setMedia(prev => [...prev, {
                id: tempId,
                url: URL.createObjectURL(file),
                type: isVideo ? "video" : "image",
                isUploading: true
            }]);

            try {
                const formData = new FormData();
                formData.append("file", file);

                const res = await fetch("/api/upload", {
                    method: "POST",
                    body: formData
                });

                if (!res.ok) {
                    throw new Error("Upload failed");
                }

                const data = await res.json();

                // Update with real URL
                setMedia(prev => prev.map(item =>
                    String(item.id) === String(tempId)
                        ? { ...item, url: data.url, isUploading: false }
                        : item
                ));
            } catch (_error) {
                // Remove failed upload
                setMedia(prev => prev.filter(item => String(item.id) !== String(tempId)));
                toast.error(language === "vi" ? `Upload ${file.name} thß║Ñt bß║íi` : `Failed to upload ${file.name}`);
            }
        }

        setIsUploading(false);
    }, [media, language]);

    // Remove media
    const removeMedia = (id: string) => {
        setMedia(prev => {
            const item = prev.find(m => String(m.id) === String(id));
            if (item && !String(item.id).startsWith("temp-")) {
                URL.revokeObjectURL(item.url);
            }
            return prev.filter(m => String(m.id) !== String(id));
        });
    };

    // Submit review
    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (rating === 0) {
            toast.error(language === "vi" ? "Vui l├▓ng chß╗ìn sß╗æ sao ─æ├ính gi├í" : "Please select a rating");
            return;
        }

        if (comment.trim().length < 10) {
            toast.error(language === "vi" ? "Vui l├▓ng nhß║¡p ─æ├ính gi├í ├¡t nhß║Ñt 10 k├╜ tß╗▒" : "Please enter at least 10 characters");
            return;
        }

        setIsSubmitting(true);

        try {
            const res = await fetch("/api/reviews", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    productId,
                    orderItemId,
                    rating,
                    comment: comment.trim(),
                    mediaUrls: media.map(m => m.url)
                })
            });

            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.error || "Failed to submit review");
            }

            toast.success(language === "vi" ? "Cß║úm ╞ín bß║ín ─æ├ú ─æ├ính gi├í!" : "Thank you for your review!");
            onSuccess?.();
        } catch (error) {
            toast.error(error instanceof Error ? error.message : (language === "vi" ? "C├│ lß╗ùi xß║úy ra" : "An error occurred"));
        } finally {
            setIsSubmitting(false);
        }
    };

