                </p>
            </div>
        );
    }

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            {/* Product Info */}
            <div className="flex items-center gap-4 p-4 bg-slate-50 rounded-2xl">
                {productImage ? (
                    <div className="relative w-16 h-16 rounded-xl overflow-hidden">
