                <div className="flex items-center gap-2">
                    {[1, 2, 3, 4, 5].map((star) => (
                        <button
                            key={star}
                            type="button"
                            onClick={() => setRating(star)}
                            onMouseEnter={() => setHoverRating(star)}
                            onMouseLeave={() => setHoverRating(0)}
                            className="p-1 transition-transform hover:scale-110"
                        >
                            <Star
                                className={`w-10 h-10 transition-colors ${star <= (hoverRating || rating)
                                        ? "fill-amber-400 text-amber-400"
                                        : "text-slate-200"
                                    }`}
                            />
                        </button>
                    ))}
                    <span className="ml-2 text-sm font-medium text-slate-500">
                        {rating > 0 && (
                            rating === 5 ? (language === "vi" ? "Tuyß╗çt vß╗¥i!" : "Excellent!") :
                                rating === 4 ? (language === "vi" ? "Rß║Ñt tß╗æt!" : "Very good!") :
                                    rating === 3 ? (language === "vi" ? "Tß╗æt" : "Good") :
                                        rating === 2 ? (language === "vi" ? "Trung b├¼nh" : "Average") :
                                            (language === "vi" ? "Kh├┤ng h├ái l├▓ng" : "Not satisfied")
                        )}
                    </span>
                </div>
            </div>

            {/* Comment */}
            <div>
                <label className="block text-sm font-bold text-slate-700 mb-3">
                    {language === "vi" ? "Nhß║¡n x├⌐t cß╗ºa bß║ín *" : "Your review *"}
                </label>
                <textarea
                    value={comment}
                    onChange={(e) => setComment(e.target.value)}
                    placeholder={language === "vi"
                        ? "Chia sß║╗ trß║úi nghiß╗çm cß╗ºa bß║ín vß╗¢i sß║ún phß║⌐m n├áy..."
                        : "Share your experience with this product..."
                    }
                    className="w-full h-32 p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary resize-none"
                    maxLength={1000}
                />
                <p className="text-xs text-slate-400 mt-1 text-right">
                    {comment.length}/1000
                </p>
            </div>

            {/* Media Upload */}
            <div>
                <label className="block text-sm font-bold text-slate-700 mb-3">
                    {language === "vi" ? "Th├¬m ß║únh/video (t├╣y chß╗ìn)" : "Add photos/videos (optional)"}
                </label>
                <div className="grid grid-cols-5 gap-3">
                    {media.map((item) => (
                        <div key={item.id} className="relative aspect-square rounded-xl overflow-hidden bg-slate-100">
                            {item.type === "video" ? (
                                <video src={item.url} className="w-full h-full object-cover" />
                            ) : (
                                <Image
                                    src={item.url}
                                    alt="Review media"
                                    fill
                                    className="object-cover"
                                    sizes="80px"
                                />
                            )}
                            {item.isUploading && (
                                <div className="absolute inset-0 bg-black/50 flex items-center justify-center">
                                    <Loader2 className="w-6 h-6 animate-spin text-white" />
                                </div>
                            )}
                            <button
                                type="button"
                                onClick={() => removeMedia(String(item.id))}
                                className="absolute top-1 right-1 w-6 h-6 bg-black/60 text-white rounded-full flex items-center justify-center hover:bg-red-500 transition-colors"
                            >
                                <X className="w-3 h-3" />
                            </button>
                        </div>
                    ))}
                    {media.length < 5 && (
                        <label className="relative aspect-square rounded-xl border-2 border-dashed border-slate-200 hover:border-primary cursor-pointer flex flex-col items-center justify-center gap-2 transition-colors">
                            <Upload className="w-6 h-6 text-slate-400" />
                            <span className="text-xs text-slate-400 font-medium">
                                {language === "vi" ? "Upload" : "Upload"}
                            </span>
                            <input
                                type="file"
                                accept="image/*,video/*"
                                multiple
                                className="absolute inset-0 opacity-0 cursor-pointer"
                                onChange={(e) => handleFileSelect(e.target.files)}
                                disabled={isUploading}
                            />
                        </label>
                    )}
                </div>
                <p className="text-xs text-slate-400 mt-2">
                    {language === "vi"
                        ? "Tß╗æi ─æa 5 ß║únh/video, mß╗ùi file tß╗æi ─æa 10MB"
                        : "Max 5 images/videos, each up to 10MB"
                    }
                </p>
            </div>

            {/* Submit Buttons */}
            <div className="flex gap-3 pt-4">
                {onCancel && (
                    <button
                        type="button"
                        onClick={onCancel}
                        className="flex-1 py-4 px-6 bg-slate-100 text-slate-700 font-bold rounded-full hover:bg-slate-200 transition-colors"
                    >
                        {language === "vi" ? "Hß╗ºy" : "Cancel"}
                    </button>
                )}
                <button
                    type="submit"
                    disabled={isSubmitting || rating === 0 || comment.trim().length < 10}
                    className="flex-1 py-4 px-6 bg-primary text-white font-bold rounded-full hover:bg-primary/90 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                >
                    {isSubmitting ? (
                        <>
                            <Loader2 className="w-5 h-5 animate-spin" />
                            {language === "vi" ? "─Éang gß╗¡i..." : "Submitting..."}
                        </>
                    ) : (
                        <>
                            <Check className="w-5 h-5" />
                            {language === "vi" ? "Gß╗¡i ─æ├ính gi├í" : "Submit Review"}
                        </>
                    )}
                </button>
            </div>
        </form>
    );
}

