/*  MAIN COMPONENT                                             */
/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */

export default function ChatbotAI() {
  const { setChatOpen } = useChatOpen();
  const { t, language, isVietnamese } = useLanguage();
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [input, setInput] = useState("");
  const [messages, setMessages] = useState<Message[]>([isVietnamese ? INITIAL_MESSAGE_VI : INITIAL_MESSAGE_EN]);
  const [isLoading, setIsLoading] = useState(false);
  const [isVisible, setIsVisible] = useState(true);
  const [lastScrollY, setLastScrollY] = useState(0);
  const [showQuickReplies, setShowQuickReplies] = useState(true);
  const [hasNotification, setHasNotification] = useState(false);
  const [notifMessage, setNotifMessage] = useState("");
  const scrollRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // ΓöÇΓöÇΓöÇ Live Chat State ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const [chatMode, setChatMode] = useState<ChatMode>("ai");
  const [liveChatId, setLiveChatId] = useState<number | null>(null);
  const [liveChatStatus, setLiveChatStatus] = useState<LiveChatStatus>(null);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isEndingLiveChat, setIsEndingLiveChat] = useState(false);
  const pollRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const lastPollTimeRef = useRef<string | null>(null);
  const closeNoticeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isShowingCloseNoticeRef = useRef(false);

  const resetToAiMode = useCallback(() => {
    if (closeNoticeTimerRef.current) {
      clearTimeout(closeNoticeTimerRef.current);
      closeNoticeTimerRef.current = null;
    }
    isShowingCloseNoticeRef.current = false;
    setChatMode("ai");
    setLiveChatId(null);
    setLiveChatStatus(null);
    lastPollTimeRef.current = null;
    if (pollRef.current) clearInterval(pollRef.current);
    setInput("");
    setShowQuickReplies(true);
    setMessages([isVietnamese ? INITIAL_MESSAGE_VI : INITIAL_MESSAGE_EN]);
  }, [isVietnamese]);

  const showClosedNoticeThenExit = useCallback(() => {
    if (isShowingCloseNoticeRef.current) return;
    isShowingCloseNoticeRef.current = true;

    if (pollRef.current) {
      clearInterval(pollRef.current);
      pollRef.current = null;
    }

    setIsLoading(false);
    setIsConnecting(false);
    setIsEndingLiveChat(false);
    setInput("");

    const closeNotice = isVietnamese
      ? "Phi├¬n chat ─æ├ú ─æ╞░ß╗úc ─æ├│ng bß╗ƒi nh├ón vi├¬n. Cß║úm ╞ín bß║ín ─æ├ú li├¬n hß╗ç LIKEFOOD! ─Éang chuyß╗ân h╞░ß╗¢ng≡ƒÖÅ"
      : "The chat session has been closed by support. Thank you for contacting LIKEFOOD! Redirecting≡ƒÖÅ";

    setMessages((prev) => {
      const exists = prev.some((m) => m.content.includes("─Éang chuyß╗ân h╞░ß╗¢ng≡ƒÖÅ") || m.content.includes("Redirecting≡ƒÖÅ"));
      if (exists) return prev;
      return [
        ...prev,
        {
          id: Date.now() + 99,
          role: "model",
          content: closeNotice,
          timestamp: new Date(),
          senderType: "ADMIN",
        },
      ];
    });

    if (closeNoticeTimerRef.current) clearTimeout(closeNoticeTimerRef.current);
    closeNoticeTimerRef.current = setTimeout(() => {
      resetToAiMode();
      setIsOpen(false);
      setIsMinimized(false);
      setChatOpen(false);
    }, 3000);
  }, [isVietnamese, resetToAiMode, setChatOpen]);

  /* ΓöÇ Scroll hide for FAB ΓöÇ */
  useEffect(() => {
    const handleScroll = () => {
      const y = window.scrollY;
      setIsVisible(y <= lastScrollY || y < 120);
      setLastScrollY(y);
    };
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, [lastScrollY]);

  /* ΓöÇ Auto-scroll on new message ΓöÇ */
  useEffect(() => {
    if (!scrollRef.current) return;
    scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: "smooth" });
  }, [messages, isLoading]);

  /* ΓöÇ Focus textarea ΓöÇ */
  useEffect(() => {
    if (isOpen && !isMinimized) textareaRef.current?.focus();
  }, [isOpen, isMinimized]);

  /* ΓöÇ Escape to close ΓöÇ */
  useEffect(() => {
    const handleEscape = (e: globalThis.KeyboardEvent) => {
      if (e.key === "Escape" && isOpen) closeAssistant();
    };
    window.addEventListener("keydown", handleEscape);
    return () => window.removeEventListener("keydown", handleEscape);
  }, [isOpen]);

  /* ΓöÇ Polling for live chat messages ΓöÇ */
  useEffect(() => {
    if (chatMode !== "live" || !liveChatId || !isOpen) {
      if (pollRef.current) {
        clearInterval(pollRef.current);
        pollRef.current = null;
      }
      return;
    }

    const poll = async (isInitialPoll = false) => {
      try {
        const sinceParam = lastPollTimeRef.current ? `?since=${lastPollTimeRef.current}` : "";
        const res = await fetch(`/api/live-chat/${liveChatId}/messages${sinceParam}`);
        if (!res.ok) return;

        const data = await res.json();
        if (data.serverTime) lastPollTimeRef.current = data.serverTime;

        if (data.chatStatus === "OPEN" || data.chatStatus === "ASSIGNED") {
          setLiveChatStatus(data.chatStatus);
        }

        if (data.chatStatus === "CLOSED") {
          showClosedNoticeThenExit();
          return;
        }

        if (data.messages?.length > 0) {
          setMessages(prev => {
            const existingIds = new Set(prev.map(m => m.id));
            const newMsgs: Message[] = data.messages
              .filter((m: { id: number; senderType: string }) => {
                if (existingIds.has(m.id)) return false;
                // Initial load: lß║Ñy tß║Ñt cß║ú (history). Subsequent polls: chß╗ë ADMIN/AI
                if (!isInitialPoll && m.senderType === "USER") return false;
                return true;
              })
              .map((m: { id: number; senderType: string; content: string; createdAt: string }) => ({
                id: m.id,
                role: m.senderType === "USER" ? "user" as const : "model" as const,
                content: m.content,
                timestamp: new Date(m.createdAt),
                senderType: m.senderType,
              }));
            return newMsgs.length > 0 ? [...prev, ...newMsgs] : prev;
          });
        }
      } catch {
        // Silent fail for polling
      }
    };

    // Initial fetch of all messages (history)
    if (!lastPollTimeRef.current) {
      void poll(true);
    }

    pollRef.current = setInterval(() => poll(false), 3000);
    return () => {
      if (pollRef.current) clearInterval(pollRef.current);
    };
  }, [chatMode, liveChatId, isOpen, resetToAiMode, showClosedNoticeThenExit]);

  /* ΓöÇ Cleanup on unmount ΓöÇ */
  useEffect(() => {
    return () => {
      if (pollRef.current) clearInterval(pollRef.current);
      if (closeNoticeTimerRef.current) clearTimeout(closeNoticeTimerRef.current);
    };
  }, []);

  const openAssistant = useCallback(() => {
    setIsOpen(true);
    setIsMinimized(false);
    setChatOpen(true);
    setHasNotification(false);
    setNotifMessage("");
  }, [setChatOpen]);

  const closeAssistant = useCallback(() => {
    setIsOpen(false);
    setIsMinimized(false);
    setChatOpen(false);
    // Hiß╗ân thß╗ï notification sau 3 gi├óy khi ─æ├│ng chat
    setTimeout(() => {
      setHasNotification(true);
      setNotifMessage(language === "vi"
        ? "Bß║ín c├│ tin nhß║»n tß╗½ LIKEFOOD AI≡ƒæï"
        : "You have a message from LIKEFOOD AI≡ƒæï");
    }, 3000);
  }, [setChatOpen, language]);

  const resetConversation = () => {
    setMessages([isVietnamese ? INITIAL_MESSAGE_VI : INITIAL_MESSAGE_EN]);
    setInput("");
    setShowQuickReplies(true);
    setChatMode("ai");
    setLiveChatId(null);
    lastPollTimeRef.current = null;
    if (pollRef.current) clearInterval(pollRef.current);
  };

  const endLiveChat = async () => {
    if (!liveChatId || chatMode !== "live") {
      resetToAiMode();
      return;
    }

    setIsEndingLiveChat(true);
    try {
      await fetch(`/api/live-chat/${liveChatId}/close`, { method: "POST" });
    } catch {
      // Even if close API fails transiently, user side still resets to a new AI conversation.
    } finally {
      showClosedNoticeThenExit();
    }
  };

  /* ΓöÇΓöÇΓöÇ Switch to Live Chat ΓöÇΓöÇΓöÇ */
  const enterLiveChatMode = () => {
    setChatMode("live");
    setLiveChatId(null);
    setLiveChatStatus(null);
    setShowQuickReplies(false);
  };

  const startLiveChatSession = async () => {
    setIsConnecting(true);
    try {
      const res = await fetch("/api/live-chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: isVietnamese
            ? "Xin ch├áo, t├┤i muß╗æn ─æ╞░ß╗úc hß╗ù trß╗ú trß╗▒c tiß║┐p."
            : "Hello, I'd like to speak with a support agent.",
          subject: "Live Chat tß╗½ Chatbot",
        }),
      });

      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        if (res.status === 401) {
          setMessages(prev => [...prev, {
            id: Date.now(),
            role: "model",
            content: isVietnamese
              ? "ΓÜá∩╕Å Bß║ín cß║ºn **─æ─âng nhß║¡p** ─æß╗â chat trß╗▒c tiß║┐p vß╗¢i nh├ón vi├¬n. Vui l├▓ng ─æ─âng nhß║¡p rß╗ôi thß╗¡ lß║íi nh├⌐!"
              : "ΓÜá∩╕Å Please **log in** to chat with a support agent.",
            timestamp: new Date(),
          }]);
          return;
        }
        throw new Error(data?.error || "Kh├┤ng thß╗â kß║┐t nß╗æi.");
      }

      const data = await res.json();
      setLiveChatId(data.chatId);
      setChatMode("live");
      // Always start in waiting state; switch to ASSIGNED only when admin clicks "Nhß║¡n xß╗¡ l├¡".
      setLiveChatStatus("OPEN");
      lastPollTimeRef.current = null;
    } catch (error) {
      setMessages(prev => [...prev, {
        id: Date.now(),
        role: "model",
        content: isVietnamese
          ? `Γ¥î ${error instanceof Error ? error.message : "Kh├┤ng thß╗â kß║┐t nß╗æi live chat."}`
          : `Γ¥î ${error instanceof Error ? error.message : "Could not connect to live chat."}`,
        timestamp: new Date(),
      }]);
    } finally {
      setIsConnecting(false);
    }
  };

  /* ΓöÇΓöÇΓöÇ Back to AI mode ΓöÇΓöÇΓöÇ */
  const switchToAI = () => {
    setChatMode("ai");
    setLiveChatId(null);
    setLiveChatStatus(null);
    lastPollTimeRef.current = null;
    if (pollRef.current) clearInterval(pollRef.current);
  };

  /* ΓöÇ Send message ΓöÇ */
  const sendMessage = async (value?: string) => {
    const nextInput = (value ?? input).trim();
    if (!nextInput || isLoading) return;

    setShowQuickReplies(false);

    const userMessage: Message = {
      id: Number(Date.now()),
      role: "user",
      content: nextInput,
      timestamp: new Date(),
      senderType: "USER",
    };

    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setIsLoading(true);

    if (textareaRef.current) textareaRef.current.style.height = "auto";

    try {
      if (chatMode === "live" && liveChatId) {
        // ΓöÇΓöÇΓöÇ Live Chat Mode: gß╗¡i qua API ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
        const res = await fetch(`/api/live-chat/${liveChatId}/messages`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ message: nextInput }),
        });

        if (!res.ok) {
          const data = await res.json().catch(() => ({}));
          if (data?.error === "Phi├¬n chat ─æ├ú ─æ╞░ß╗úc ─æ├│ng.") {
            showClosedNoticeThenExit();
            return;
          }
          throw new Error(data?.error || "Kh├┤ng thß╗â gß╗¡i tin nhß║»n.");
        }

        // Update local message ID with server DB ID to prevent polling duplicates
        const data = await res.json();
        if (data.message?.id) {
          setMessages(prev =>
            prev.map(m =>
              m.id === userMessage.id ? { ...m, id: data.message.id } : m
            )
          );
        }

        // Live Chat: KH├öNG tß╗▒ trß║ú lß╗¥i ΓÇö chß╗ë chß╗¥ nh├ón vi├¬n
        // Message ─æ├ú ─æ╞░ß╗úc gß╗¡i vß╗ü server ΓåÆ Telegram notification tß╗▒ ─æß╗Öng
      } else {
        // ΓöÇΓöÇΓöÇ AI Chat Mode: SSE Streaming ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
        const currentMsgId = Number(Date.now()) + 1;
        // Add an empty model message that will be filled by streaming
        setMessages((prev) => [...prev, {
          id: currentMsgId,
          role: "model" as const,
          content: "",
          timestamp: new Date(),
          senderType: "AI" as const,
        }]);

        const response = await fetch("/api/ai/chat/stream", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            message: nextInput,
            sessionId: analytics.getSessionId(),
            history: messages.slice(-6).map((m) => ({ role: m.role, content: m.content })),
          }),
        });

        if (!response.ok) {
          const errData = await response.json().catch(() => ({}));
          throw new Error(errData?.error || errData?.message || (isVietnamese ? "Kh├┤ng thß╗â kß║┐t nß╗æi. Vui l├▓ng thß╗¡ lß║íi!" : "Connection failed. Please try again!"));
        }

        // Parse SSE stream
        if (response.body) {
          // Tß║»t loading indicator ΓÇö stream message tß╗▒ hiß╗çn content real-time
          setIsLoading(false);
          const reader = response.body.getReader();
          const decoder = new TextDecoder();
          let fullContent = "";

          try {
            while (true) {
              const { done, value } = await reader.read();
              if (done) break;

              const text = decoder.decode(value, { stream: true });
              const lines = text.split("\n");

              for (const line of lines) {
                const trimmedLine = line.trim();
                if (!trimmedLine || !trimmedLine.startsWith("data: ")) continue;

                try {
                  const dataStr = trimmedLine.slice(6);
                  const evt = JSON.parse(dataStr);
                  const content = evt?.data?.content || evt?.content || "";
                  if (content) {
                    fullContent = content;
                    setMessages((prev) =>
                      prev.map((m) =>
                        m.id === currentMsgId ? { ...m, content: fullContent } : m
                      )
                    );
                  }
                } catch {
                  // Skip invalid JSON lines (e.g. event types)
                }
              }
            }
          } catch {
            // Stream ended or error ΓÇö use whatever we have
          }

          // Ensure we have content, otherwise show error
          if (!fullContent) {
            setMessages((prev) =>
              prev.map((m) =>
                m.id === currentMsgId
                  ? { ...m, content: isVietnamese ? "M├¼nh ─æang cß║¡p nhß║¡t dß╗» liß╗çu. Bß║ín thß╗¡ hß╗Åi lß║íi nh├⌐! ≡ƒÿè" : "I'm updating data. Please try again! ≡ƒÿè" }
                  : m
              )
            );
          }
        } else {
          // Fallback: no streaming support ΓÇö try json
          const data = await response.json().catch(() => ({}));
          const replyContent = data.content ?? data.response ?? (isVietnamese ? "M├¼nh ─æang cß║¡p nhß║¡t. Bß║ín thß╗¡ hß╗Åi lß║íi nh├⌐! ≡ƒÿè" : "Updating. Please try again! ≡ƒÿè");
          setMessages((prev) =>
            prev.map((m) =>
              m.id === currentMsgId ? { ...m, content: replyContent } : m
            )
          );
        }
      }
    } catch (error) {
      setMessages((prev) => [
        ...prev,
        {
          id: Date.now() + 2,
          role: "model",
          content: error instanceof Error ? error.message : (isVietnamese ? "Kß║┐t nß╗æi tß║ím gi├ín ─æoß║ín. Thß╗¡ lß║íi sau ├¡t ph├║t nh├⌐! ≡ƒÖÅ" : "Connection interrupted. Try again later! ≡ƒÖÅ"),
          timestamp: new Date(),
        },
      ]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (event: KeyboardEvent<HTMLTextAreaElement>) => {
    if (event.key === "Enter" && !event.shiftKey) {
      event.preventDefault();
      void sendMessage();
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setInput(e.target.value);
    const el = e.target;
    el.style.height = "auto";
    el.style.height = Math.min(el.scrollHeight, 120) + "px";
  };

  const headerGradient = chatMode === "live"
    ? "from-blue-600 via-indigo-600 to-purple-600"
