                        </p>
                        {chatMode === "ai" && <Sparkles className="h-3.5 w-3.5 text-amber-300" />}
                      </div>
                      <p className="text-[11px] text-white/80 font-medium">
                        {chatMode === "live"
                          ? (isVietnamese ? "Chat trß╗▒c tiß║┐p vß╗¢i nh├ón vi├¬n" : "Live chat with support")
                          : isLoading
                            ? (isVietnamese ? "─Éang soß║ín tin nhß║»n..." : "Typing...")
                            : (isVietnamese ? "Trß╗▒c tuyß║┐n ΓÇó Sß║╡n s├áng hß╗ù trß╗ú" : "Online ΓÇó Ready to help")}
                      </p>
                    </div>
                    <div className="flex items-center gap-1">
                      {/* Switch mode button */}
                      {chatMode === "live" ? (
                        <>
                          <button
                            onClick={switchToAI}
                            className="flex h-8 items-center gap-1 rounded-full bg-white/15 px-2.5 text-[10px] font-bold text-white transition hover:bg-white/25"
