                            title={isVietnamese ? "Kß║┐t th├║c ─æoß║ín chat" : "End chat session"}
                            aria-label={isVietnamese ? "Kß║┐t th├║c ─æoß║ín chat" : "End current chat session"}
                          >
                            <X className="h-3 w-3" />
                            {isEndingLiveChat
                              ? (isVietnamese ? "─Éang ─æ├│ng..." : "Closing...")
                              : (isVietnamese ? "Kß║┐t th├║c ─æoß║ín chat" : "End chat")}
                          </button>
                        </>
                      ) : (
                        <button
