                      </button>
                    </div>
                  </div>
                </div>

                {isMinimized ? (
                  <div className="flex items-center justify-between px-4 py-3">
                    <span className="text-sm text-slate-600">{isVietnamese ? "Cuß╗Öc tr├▓ chuyß╗çn ─æang chß╗¥..." : "Conversation on hold..."}</span>
                    <button
                      onClick={() => setIsMinimized(false)}
