                <span className="combo-final">${combo.finalPrice.toFixed(2)}</span>
              </div>
              <span className="combo-savings">Tiß║┐t kiß╗çm ${combo.savings.toFixed(2)}</span>
            </div>

            <div className="combo-reason">
              <span>≡ƒÆí {combo.reason}</span>
