    fullName: string;
    phone: string;
    address: string;
    city: string;
    state?: string | null;
    zipCode: string;
    country: string;
    isDefault: boolean;
}

export type PaymentMethod = "STRIPE" | "PICKUP";

export interface CheckoutVoucher {
    id: number;
    code: string;
    discountType: "PERCENTAGE" | "FIXED";
    discountValue: number;
    discountAmount: number;
    minOrderValue: number | null;
    maxDiscount: number | null;
    category: string;
    canUse: boolean;
    reason: string;
}

export interface CheckoutFormData {
    fullName: string;
    email: string;
    phone: string;
    address: string;
    city: string;
    state: string;
    zipCode: string;
    shippingMethod: string;
}



// ΓöÇΓöÇΓöÇ Hook ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export function useCheckout(language: string) {
    const router = useRouter();
    const { data: session } = useSession();
    const { items, totalPrice, clearCart } = useCart();


    // ΓöÇΓöÇ Core State ΓöÇΓöÇ
    const [step, setStep] = useState(1);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [orderId, setOrderId] = useState<number | null>(null);
    const [formErrors, setFormErrors] = useState<Record<string, string>>({});

    // ΓöÇΓöÇ Form Data ΓöÇΓöÇ
    const [formData, setFormData] = useState<CheckoutFormData>({
        fullName: "",
        email: "",
        phone: "",
        address: "",
        city: "",
        state: "",
        zipCode: "",
        shippingMethod: "standard",
    });
    const [saveInfo, setSaveInfo] = useState(false);
    const [orderNotes, setOrderNotes] = useState("");

    // ΓöÇΓöÇ Address Book ΓöÇΓöÇ
    const [addresses, setAddresses] = useState<CheckoutAddress[]>([]);
    const [isLoadingAddresses, setIsLoadingAddresses] = useState(false);
    const [selectedAddressId, setSelectedAddressId] = useState<number | null>(null);

    // ΓöÇΓöÇ Voucher & Points ΓöÇΓöÇ
    const [selectedVoucher, setSelectedVoucher] = useState<CheckoutVoucher | null>(null);
    const [showVoucherModal, setShowVoucherModal] = useState(false);
    const [userPoints, setUserPoints] = useState(0);
    const [usePoints, setUsePoints] = useState(false);
    const [pointsToUse, setPointsToUse] = useState(0);

    // ΓöÇΓöÇ Payment ΓÇö Stripe only ΓöÇΓöÇ
    const [paymentMethod] = useState<PaymentMethod>("STRIPE");

    // ΓöÇΓöÇ Computed Values ΓöÇΓöÇ
    const shippingFee = useMemo(
        () => getShippingFeeUsd(totalPrice, formData.shippingMethod),
        [formData.shippingMethod, totalPrice]
    );

    const isPickup = formData.shippingMethod === "pickup";

    const pointsDiscount = useMemo(
        () => (usePoints ? pointsToUse / 100 : 0),
        [usePoints, pointsToUse]
    );

    const finalTotal = useMemo(() => {
        const discount = selectedVoucher?.discountAmount || 0;
        return Math.max(0, totalPrice + shippingFee - discount - pointsDiscount);
    }, [totalPrice, shippingFee, selectedVoucher, pointsDiscount]);

    const isCartEmpty = items.length === 0 && step < 3;

    // ΓöÇΓöÇ Load saved checkout info from localStorage ΓöÇΓöÇ
    useEffect(() => {
        const savedInfo = localStorage.getItem("checkout_info");
        if (savedInfo && !session?.user) {
            try {
                const parsed = JSON.parse(savedInfo);
                setFormData(prev => ({
                    ...prev,
                    fullName: parsed.fullName || "",
                    email: parsed.email || "",
                    phone: parsed.phone || "",
                    address: parsed.address || "",
                    city: parsed.city || "",
                    zipCode: parsed.zipCode || "",
                }));
                setSaveInfo(true);
            } catch (e) {
                console.error("Failed to load saved checkout info", e);
            }
        }
    }, [session]);

    // ΓöÇΓöÇ Load user points ΓöÇΓöÇ
    useEffect(() => {
        if (!session?.user) return;
        const loadPoints = async () => {
            try {
                const res = await fetch("/api/user/points");
                if (res.ok) {
                    const data = await res.json();
                    setUserPoints(data.points || 0);
                }
            } catch (err) {
                console.error("Failed to load user points", err);
            }
        };
        loadPoints();
    }, [session]);



    // ΓöÇΓöÇ Load saved addresses ΓöÇΓöÇ
    useEffect(() => {
        if (!session?.user) return;
        const loadAddresses = async () => {
            try {
                setIsLoadingAddresses(true);
                const res = await fetch("/api/user/addresses");
                if (!res.ok) return;
                const data: CheckoutAddress[] = await res.json();
                setAddresses(data);
                if (data.length > 0) {
                    const defaultAddr = data.find(a => a.isDefault) || data[0];
                    setSelectedAddressId(defaultAddr.id);
                    setFormData(prev => ({
                        ...prev,
                        fullName: defaultAddr.fullName,
                        phone: defaultAddr.phone,
                        address: defaultAddr.address,
                        city: defaultAddr.city,
                        zipCode: defaultAddr.zipCode,
                    }));
                }
            } catch (err) {
                logger.error("Failed to load addresses for checkout", err as Error, { context: "checkout-page" });
            } finally {
                setIsLoadingAddresses(false);
            }
        };
        loadAddresses();
    }, [session]);

    // ΓöÇΓöÇ Auto-apply best voucher ΓöÇΓöÇ
    useEffect(() => {
        if (!session?.user || selectedVoucher || totalPrice === 0) return;
        const autoApplyVoucher = async () => {
            try {
                const res = await fetch(`/api/vouchers/checkout?orderTotal=${totalPrice}`);
                if (res.ok) {
                    const data = await res.json();
                    const vouchers = data.vouchers || [];
                    const bestVoucher = vouchers.find((v: CheckoutVoucher) => v.canUse);
                    if (bestVoucher) setSelectedVoucher(bestVoucher);
                }
            } catch (error) {
                logger.warn("Failed to auto-apply voucher", { context: "checkout-page", error: error as Error });
            }
        };
        autoApplyVoucher();
    }, [session, totalPrice, selectedVoucher]);

    // ΓöÇΓöÇ Validation ΓöÇΓöÇ
    const validateForm = useCallback((): boolean => {
        const errors: Record<string, string> = {};

        if (!formData.fullName.trim()) {
            errors.fullName = language === "vi" ? "Vui l├▓ng nhß║¡p hß╗ì t├¬n" : "Full name is required";
        }
        if (!formData.email.trim()) {
            errors.email = language === "vi" ? "Vui l├▓ng nhß║¡p email" : "Email is required";
        } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
            errors.email = language === "vi" ? "Email kh├┤ng hß╗úp lß╗ç" : "Invalid email format";
        }
        if (!formData.phone.trim()) {
            errors.phone = language === "vi" ? "Vui l├▓ng nhß║¡p sß╗æ ─æiß╗çn thoß║íi" : "Phone number is required";
        }
        // Skip address validation for pickup
        if (formData.shippingMethod !== "pickup") {
            if (!formData.address.trim()) {
                errors.address = language === "vi" ? "Vui l├▓ng nhß║¡p ─æß╗ïa chß╗ë" : "Address is required";
            }
            if (!formData.city.trim()) {
                errors.city = language === "vi" ? "Vui l├▓ng nhß║¡p th├ánh phß╗æ" : "City is required";
            }
        }

        setFormErrors(errors);
        if (Object.keys(errors).length > 0) {
            toast.error(language === "vi" ? "Vui l├▓ng ─æiß╗ün ─æß║ºy ─æß╗º th├┤ng tin" : "Please fill in all required information");
            return false;
        }
        return true;
    }, [formData, language]);

    // ΓöÇΓöÇ Navigation ΓöÇΓöÇ
    const nextStep = useCallback(() => {
        if (step === 1 && !validateForm()) return;
        setStep(s => s + 1);
    }, [step, validateForm]);
    const prevStep = useCallback(() => setStep(s => s - 1), []);

    // ΓöÇΓöÇ Select Address ΓöÇΓöÇ
    const selectAddress = useCallback((addr: CheckoutAddress) => {
        setSelectedAddressId(addr.id);
        setFormData(prev => ({
            ...prev,
            fullName: addr.fullName,
            phone: addr.phone,
            address: addr.address,
            city: addr.city,
            zipCode: addr.zipCode,
        }));
    }, []);

    // ΓöÇΓöÇ Toggle Points ΓöÇΓöÇ
    const togglePoints = useCallback(() => {
        const newVal = !usePoints;
        setUsePoints(newVal);
        if (newVal) {
            setPointsToUse(
                Math.min(userPoints, Math.floor((totalPrice - (selectedVoucher?.discountAmount || 0)) * 100))
            );
        }
    }, [usePoints, userPoints, totalPrice, selectedVoucher]);

    // ΓöÇΓöÇ Update form field ΓöÇΓöÇ
    const updateField = useCallback((field: keyof CheckoutFormData, value: string) => {
        setFormData(prev => ({ ...prev, [field]: value }));
        // Clear error khi user bß║»t ─æß║ºu sß╗¡a field
        if (formErrors[field]) {
            setFormErrors(prev => {
                const next = { ...prev };
                delete next[field];
                return next;
            });
        }
    }, [formErrors]);

    // ΓöÇΓöÇ Handle Checkout Submission ΓöÇΓöÇ
    const handleOrder = useCallback(async () => {
        if (isSubmitting) return;
        if (!validateForm()) return;
        setIsSubmitting(true);
        try {
            // Stock check
            try {
                const stockRes = await fetch("/api/products/check-stock", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        items: items.map(item => ({
                            productId: item.productId,
                            variantId: item.variantId || null,
                            quantity: item.quantity,
                        })),
                    }),
                });
                if (stockRes.ok) {
                    const stockData = await stockRes.json();
                    if (stockData.outOfStock && stockData.outOfStock.length > 0) {
                        const names = stockData.outOfStock.map((i: { name: string }) => i.name).join(", ");
                        toast.error(
                            language === "vi"
