    `- T├¬n: ${profile.name}, Ph├ón kh├║c: ${profile.segment}`,
    `- Tß╗òng chi: ${formatCurrency(profile.totalSpent)}, Danh mß╗Ñc: ${profile.topCategories.join(", ") || "Ch╞░a r├╡"}`,
    `- SP ─æang xem: ${profile.recentProducts.slice(0, 3).map(p => p.name).join(", ") || "Ch╞░a r├╡"}`,
    `- Giß╗Å h├áng: ${profile.cartItems.length > 0 ? profile.cartItems.map(i => i.name).join(", ") : "Trß╗æng"}`,
    "Kß╗ïch bß║ún tß╗▒ nhi├¬n, th├ón thiß╗çn, ─æß╗ü xuß║Ñt SP ph├╣ hß╗úp.",
  ].join("\n");

  const salesScript = await askAI(scriptPrompt, `Ch├áo ${profile.name}! Cß║úm ╞ín bß║ín ─æ├ú quay lß║íi LIKEFOOD. Bß║ín cß║ºn t╞░ vß║Ñn g├¼ th├¬m kh├┤ng ß║í?`);
  const customerInsight = profile.behaviorInsights.join(". ") || "Ch╞░a c├│ ─æß╗º dß╗» liß╗çu h├ánh vi.";

  let urgencyLevel: 'high' | 'medium' | 'low' = 'low';
  if (profile.purchaseProbability > 70) urgencyLevel = 'high';
