export async function searchProductsDetailed(query: string, limit = 8): Promise<ProductDetail[]> {
  try {
    const keywords = query
      .toLowerCase()
      .replace(/[^a-zA-Z0-9├á├íß║íß║ú├ú├óß║ºß║Ñß║¡ß║⌐ß║½─âß║▒ß║»ß║╖ß║│ß║╡├¿├⌐ß║╣ß║╗ß║╜├¬ß╗üß║┐ß╗çß╗âß╗à├¼├¡ß╗ïß╗ë─⌐├▓├│ß╗ìß╗Å├╡├┤ß╗ôß╗æß╗Öß╗òß╗ù╞íß╗¥ß╗¢ß╗úß╗ƒß╗í├╣├║ß╗Ñß╗º┼⌐╞░ß╗½ß╗⌐ß╗▒ß╗¡ß╗»ß╗│├╜ß╗╡ß╗╖ß╗╣─æ\s]/g, "")
      .split(/\s+/)
      .filter(w => w.length > 1);

    if (keywords.length === 0) return [];

    const products = await prisma.product.findMany({
      where: {
        isDeleted: false,
        inventory: { gt: 0 },
        OR: keywords.flatMap(term => [
          { name: { contains: term } },
          { description: { contains: term } },
          { category: { contains: term } },
        ]),
      },
      include: { brand: { select: { name: true } } },
      orderBy: { soldCount: "desc" },
      take: limit,
    });

    return products.map(mapProductDetail);
  } catch (error) {
    console.error("[AI_DATA_ENHANCED] searchProductsDetailed error:", error);
    return [];
  }
}

