// ΓöÇΓöÇΓöÇ 6. Get Flash Sale ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export async function getFlashSaleInfo(): Promise<string> {
  try {
    const now = new Date();
    const sale = await prisma.flashsalecampaign.findFirst({
      where: {
        isActive: true,
        startAt: { lte: now },
        endAt: { gte: now },
      },
      include: {
        products: {
          include: {
            product: {
              select: {
                name: true, price: true, salePrice: true, slug: true,
              },
            },
          },
          take: 6,
        },
      },
    });

    if (!sale) return "";

    const products = sale.products.map(item => {
      const p = item.product;
      const discount = p.salePrice ? Math.round((1 - p.salePrice / p.price) * 100) : 0;
      return `- **${p.name}**: $${p.price} ΓåÆ $${p.salePrice} (-${discount}%)`;
    }).join("\n");

    return `\n≡ƒöÑ FLASH SALE ─ÉANG DIß╗äN RA: "${sale.name}"\n${products}`;
  } catch {
    return "";
  }
}

// ΓöÇΓöÇΓöÇ 7. Get User Profile (if logged in) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export async function getUserProfileContext(userId: number): Promise<string> {
  try {
    const orders = await prisma.order.findMany({
      where: { userId, status: { in: ["DELIVERED", "COMPLETED", "SHIPPED", "CONFIRMED"] } },
      include: {
        orderItems: {
          include: { product: { select: { name: true, category: true } } },
        },
      },
      orderBy: { createdAt: "desc" },
      take: 5,
    });

    if (orders.length === 0) return "";

    const categoryCounts: Record<string, number> = {};
    const recentProducts: string[] = [];

    for (const order of orders.slice(0, 3)) {
      for (const item of order.orderItems) {
        const cat = item.product?.category ?? "unknown";
        categoryCounts[cat] = (categoryCounts[cat] || 0) + item.quantity;
        if (recentProducts.length < 5 && item.product?.name) {
          recentProducts.push(item.product.name);
        }
      }
    }

    const favoriteCats = Object.entries(categoryCounts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 3)
      .map(([cat]) => cat);

    const totalSpent = orders.reduce((s, o) => s + (o.total ?? 0), 0);

    return `\n≡ƒæñ TH├öNG TIN KH├üCH H├ÇNG:\n` +
      `- ─É├ú mua: ${orders.length} ─æ╞ín h├áng\n` +
      `- Tß╗òng chi: $${totalSpent.toFixed(2)}\n` +
      `- Danh mß╗Ñc y├¬u th├¡ch: ${favoriteCats.join(", ")}\n` +
      `- Sß║ún phß║⌐m gß║ºn mua: ${recentProducts.join(", ")}`;
  } catch {
    return "";
  }
}

