// ΓöÇΓöÇΓöÇ Save combo to DB ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

async function saveComboToDB(combo: ComboResult): Promise<number> {
  const saved = await prisma.aiCombo.create({
    data: {
      name: combo.name,
      nameEn: combo.nameEn,
      type: combo.type,
      description: combo.description,
      totalPrice: combo.totalPrice,
      discountPct: combo.discountPct,
      finalPrice: combo.finalPrice,
      reason: combo.reason,
      items: {
        create: combo.products.map(p => ({
          productId: p.id,
          quantity: p.quantity,
        })),
      },
    },
  });
  return saved.id;
}

