function detectSentiment(text: string): "positive" | "negative" | "neutral" {
  const lower = text.toLowerCase();
  const positiveWords = ["ngon", "tuyß╗çt", "tß╗æt", " tuyß╗çt vß╗¥i", "awesome", "great", "good", "love", "perfect", "excellent", "happy", "h├ái l├▓ng", "th├¡ch", "╞░ng ├╜", "ok", "okay", "─æ╞░ß╗úc", "nice", "wonderful", "fantastic"];
  const negativeWords = ["tß╗ç", "k├⌐m", "kh├┤ng", "bad", "poor", "terrible", "hate", "disappointed", "thß║Ñt vß╗ìng", "kh├┤ng h├ái l├▓ng", "tß╗⌐c", "bß╗▒c", "mß╗çt", "ch├ín", "─æi├¬n", "─æß║¡p", "h├⌐t", "mß║»ng", "qu├ít", "mß║»ng", "wrong", "issue", "problem", "lß╗ùi", "sai", "hß╗Ång", "h╞░", "bay giß╗¥", "never", "waste", "tiß║┐c"];

  const hasPositive = positiveWords.some(w => lower.includes(w));
  const hasNegative = negativeWords.some(w => lower.includes(w));

  if (hasNegative && !hasPositive) return "negative";
  if (hasPositive && !hasNegative) return "positive";
  return "neutral";
}

