function getCategoryAnalysis(category: string) {
  const catKey = Object.keys(CATEGORY_ANALYSIS).find(k => 
    category.toLowerCase().includes(k.toLowerCase())
  );
  return CATEGORY_ANALYSIS[catKey || "default"];
}

function detectCategory(text: string): string {
  const lower = text.toLowerCase();
  if (lower.includes("tr├á") || lower.includes("tea")) return "Tr├á";
  if (lower.includes("c├á ph├¬") || lower.includes("coffee")) return "C├á ph├¬";
  if (lower.includes("c├í") && lower.includes("kh├┤")) return "C├í kh├┤";
  if (lower.includes("t├┤m") && lower.includes("kh├┤")) return "T├┤m kh├┤";
  if (lower.includes("mß╗▒c") && lower.includes("kh├┤")) return "Mß╗▒c kh├┤";
  if (lower.includes("n╞░ß╗¢c mß║»m") || lower.includes("fish sauce")) return "N╞░ß╗¢c mß║»m";
  if (lower.includes("b├ính")) return "B├ính";
  if (lower.includes("kß║╣o") || lower.includes("candy")) return "Kß║╣o";
  if (lower.includes("mß╗⌐t")) return "Mß╗⌐t";
  if (lower.includes("hoa quß║ú") || lower.includes("tr├íi c├óy") || lower.includes("fruit")) return "Hoa quß║ú sß║Ñy";
  if (lower.includes("kh├┤ b├▓") || lower.includes("beef")) return "Kh├┤ b├▓";
  if (lower.includes("kh├┤ g├á") || lower.includes("chicken")) return "Kh├┤ g├á";
  return "default";
}

async function askAI(prompt: string): Promise<string> {
  const result = await callGPTJSON<Record<string, unknown>>(prompt, {
    task: "product-analysis",
    temperature: 0.4,
    maxTokens: 1200,
  });
  return result ? JSON.stringify(result) : "";
}

