export async function analyzeAllProducts(): Promise<ProductAnalysis[]> {
  const products = await prisma.product.findMany({
    where: { isDeleted: false },
    select: {
      id: true,
      name: true,
      slug: true,
      description: true,
      price: true,
      salePrice: true,
      saleStartAt: true,
      saleEndAt: true,
      category: true,
      categoryId: true,
      brandId: true,
      tags: true,
      image: true,
      inventory: true,
      soldCount: true,
      ratingAvg: true,
      ratingCount: true,
      weight: true,
      code: true,
      badgeText: true,
      isOnSale: true,
      featured: true,
      isVisible: true,
      originalPrice: true
    },
    take: 111
  });

  const analyses: ProductAnalysis[] = [];
  
  for (const product of products) {
    const analysis = await analyzeProduct(product as ProductWithDetails);
    analyses.push(analysis);
  }

  return analyses;
}

