export async function generateProductInsights(): Promise<{
  totalProducts: number;
  categories: { name: string; count: number }[];
  priceRange: { min: number; max: number; avg: number };
  topProducts: { id: number; name: string; sold: number }[];
  lowStock: { id: number; name: string; stock: number }[];
  insights: string[];
}> {
  const [products, categoryGroups, lowStockProducts, topSold] = await Promise.all([
    prisma.product.findMany({
      where: { isDeleted: false },
      select: { id: true, name: true, price: true, category: true, soldCount: true }
    }),
    prisma.product.groupBy({
      by: ["category"],
      where: { isDeleted: false },
      _count: { id: true }
    }),
    prisma.product.findMany({
      where: { isDeleted: false, inventory: { lt: 10 } },
      select: { id: true, name: true, inventory: true },
      orderBy: { inventory: "asc" },
      take: 10
    }),
    prisma.product.findMany({
      where: { isDeleted: false },
      select: { id: true, name: true, soldCount: true },
      orderBy: { soldCount: "desc" },
      take: 10
    })
  ]);

  const prices = products.map(p => p.price);
  const priceRange = {
    min: Math.min(...prices),
    max: Math.max(...prices),
    avg: prices.reduce((a, b) => a + b, 0) / prices.length
  };

  const prompt = `
Dß╗▒a tr├¬n dß╗» liß╗çu sß║ún phß║⌐m LIKEFOOD:
- Tß╗òng sß║ún phß║⌐m: ${products.length}
- Danh mß╗Ñc: ${categoryGroups.map(c => `${c.category}: ${c._count.id}`).join(", ")}
- Khoß║úng gi├í: $${priceRange.min.toFixed(2)} - $${priceRange.max.toFixed(2)} (TB: $${priceRange.avg.toFixed(2)})
- Top b├ín chß║íy: ${topSold.map(p => p.name).slice(0, 5).join(", ")}
- Sß║ún phß║⌐m sß║»p hß║┐t h├áng: ${lowStockProducts.map(p => p.name).join(", ")}

H├úy ─æ╞░a ra 5 insights ngß║»n gß╗ìn vß╗ü danh mß╗Ñc sß║ún phß║⌐m bß║▒ng tiß║┐ng Viß╗çt.
Chß╗ë trß║ú vß╗ü JSON array c├íc string, kh├┤ng giß║úi th├¡ch.
`;

  const insights: string[] = [
    `C├│ ${products.length} sß║ún phß║⌐m ─æang b├ín`,
    `${categoryGroups.length} danh mß╗Ñc sß║ún phß║⌐m`,
    `Gi├í trung b├¼nh: $${priceRange.avg.toFixed(2)}`,
    `${lowStockProducts.length} sß║ún phß║⌐m sß║»p hß║┐t h├áng`,
    "Top sß║ún phß║⌐m b├ín chß║íy ─æang ─æ╞░ß╗úc cß║¡p nhß║¡t"
  ];

  const aiInsights = await askAI(prompt);
  if (aiInsights) {
    try {
      const parsed = JSON.parse(aiInsights);
      if (Array.isArray(parsed)) {
        insights.length = 0;
        insights.push(...parsed.slice(0, 5));
      }
    } catch (e) {}
  }

  return {
    totalProducts: products.length,
    categories: categoryGroups.map(c => ({ name: c.category, count: c._count.id })),
    priceRange,
    topProducts: topSold.map(p => ({ id: p.id, name: p.name, sold: p.soldCount })),
    lowStock: lowStockProducts.map(p => ({ id: p.id, name: p.name, stock: p.inventory })),
    insights
  };
}

