async function getAllProductsDetailed(): Promise<string> {
  try {
    const products = await prisma.product.findMany({
      where: { isDeleted: false },
      select: {
        id: true, name: true, slug: true, price: true, salePrice: true,
        category: true, brand: true, description: true, ratingAvg: true,
        ratingCount: true, soldCount: true, inventory: true, isOnSale: true,
        weight: true,
      },
      orderBy: [{ soldCount: "desc" }, { name: "asc" }],
      take: 200,
    });

    if (products.length === 0) return "Γ¥î Kh├┤ng c├│ sß║ún phß║⌐m n├áo";

    const lines = [`≡ƒôª Tß║ñT Cß║ó Sß║óN PHß║¿M (${products.length} sß║ún phß║⌐m):`];

    // Group by category
    const byCategory: Record<string, ProductInfo[]> = {};
    for (const p of products) {
      const cat = p.category || "Kh├íc";
      if (!byCategory[cat]) byCategory[cat] = [];
      byCategory[cat].push(p as ProductInfo);
    }

    for (const [cat, items] of Object.entries(byCategory)) {
      lines.push(`\n≡ƒôé ${cat.toUpperCase()} (${items.length} sß║ún phß║⌐m):`);

      for (const p of items.slice(0, 20)) { // Max 20 per category
        const sale = p.salePrice ? ` ΓÜíSALE $${p.salePrice}` : "";
        const discount = p.salePrice ? ` (-${Math.round((1 - p.salePrice / p.price) * 100)}%)` : "";
        const stock = p.inventory <= 0 ? " Γ¥îHß║╛T H├ÇNG" : p.inventory < 10 ? ` ΓÜá∩╕ÅC├▓n ${p.inventory} SP` : "";
        const rating = p.ratingAvg ? ` Γ¡É${p.ratingAvg.toFixed(1)}` : "";
        const brand = p.brand?.name ? ` ≡ƒÅ¡${p.brand.name}` : "";

        lines.push(`ΓÇó ${p.name}${brand} ΓÇö **$${p.price}**${discount}${sale}${stock}${rating}`);

        // Add description if available
        if (p.description && p.description.length > 20) {
          lines.push(`  ΓööΓöÇ ${p.description.slice(0, 100)}...`);
        }
      }

      if (items.length > 20) {
        lines.push(`  ΓööΓöÇ ...v├á ${items.length - 20} sß║ún phß║⌐m kh├íc`);
      }
    }

    return lines.join("\n");
  } catch (error) {
    console.error("[ULTIMATE_DATA] getAllProductsDetailed error:", error);
    return "Γ¥î Kh├┤ng thß╗â tß║úi danh s├ích sß║ún phß║⌐m";
  }
}

