// ΓöÇΓöÇΓöÇ 15. Search Products by Query ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

async function searchProductsContext(query: string): Promise<string> {
  try {
    const keywords = query.toLowerCase().split(/\s+/).filter(w => w.length > 1);
    if (keywords.length === 0) return "";

    const products = await prisma.product.findMany({
      where: {
        isDeleted: false,
        OR: keywords.flatMap(term => [
          { name: { contains: term, mode: "insensitive" } },
          { description: { contains: term, mode: "insensitive" } },
          { category: { contains: term, mode: "insensitive" } },
        ]),
      },
      include: {
        brand: true,
        reviews: { where: { status: "APPROVED" }, take: 3 },
      },
      orderBy: { soldCount: "desc" },
      take: 15,
    });

    if (products.length === 0) return "";

    const lines = [`\n≡ƒöì Kß║╛T QUß║ó T├îM KIß║╛M CHO "${query}":`];

    for (const p of products) {
      const sale = p.salePrice ? ` ΓåÆ $${p.salePrice} (-${Math.round((1 - p.salePrice / p.price) * 100)}%)` : "";
      const stock = p.inventory <= 0 ? " Γ¥îHß║╛T H├ÇNG" : p.inventory < 10 ? ` ΓÜá∩╕ÅC├▓n ${p.inventory}` : ` Γ£àC├▓n ${p.inventory}`;
      const rating = p.ratingAvg ? ` Γ¡É${p.ratingAvg.toFixed(1)} (${p.ratingCount} ─æ├ính gi├í)` : "";
      const brand = p.brand?.name ? ` ≡ƒÅ¡${p.brand.name}` : "";

      lines.push(`\n≡ƒôª ${p.name}${brand}`);
      lines.push(`   ≡ƒÆ░ Gi├í: **$${p.price}**${sale}`);
      lines.push(`   ≡ƒôª Kho: ${stock}`);
      lines.push(`   Γ¡É ${rating}`);
      lines.push(`   ≡ƒÅ╖∩╕Å Danh mß╗Ñc: ${p.category}`);

      if (p.description) {
        lines.push(`   ≡ƒô¥ ${p.description.slice(0, 100)}...`);
      }

      // Show reviews
      if (p.reviews.length > 0) {
        lines.push(`   ≡ƒÆ¼ ─É├ính gi├í:`);
        for (const r of p.reviews.slice(0, 2)) {
          const stars = "Γ¡É".repeat(r.rating);
          const comment = r.comment ? `: "${r.comment.slice(0, 60)}..."` : "";
          lines.push(`      - ${stars} ${comment}`);
        }
      }
    }

    return lines.join("\n");
  } catch {
    return "";
  }
}

