/**
 * Currency formatting utilities for the storefront and admin UI.
 * The application is standardized on USD.
 */

export type Currency = "USD";

export interface CurrencyConfig {
    currency?: Currency;
    locale?: string;
}

const DEFAULT_CURRENCY: Currency = "USD";
const DEFAULT_LOCALE = "en-US";

/** Exchange rate: 1 USD Γëê 26,000 VND */
export const USD_TO_VND_RATE = 26000;

export function setDefaultCurrency(_currency: Currency) {
    // Currency is fixed to USD for this application.
}

export function getDefaultCurrency(): Currency {
    return DEFAULT_CURRENCY;
}

export function formatPrice(price: number, config?: CurrencyConfig): string {
    return new Intl.NumberFormat(config?.locale || DEFAULT_LOCALE, {
        style: "currency",
        currency: DEFAULT_CURRENCY,
        minimumFractionDigits: 0,
        maximumFractionDigits: 2,
    }).format(price || 0);
}

export function formatPriceNumber(price: number, config?: CurrencyConfig): string {
    return new Intl.NumberFormat(config?.locale || DEFAULT_LOCALE, {
        minimumFractionDigits: 0,
        maximumFractionDigits: 2,
    }).format(price || 0);
}

export function getCurrencySymbol(_currency?: Currency): string {
    return "$";
}

/**
 * Format VND equivalent of a USD price.
 * Example: formatVndEquivalent(10) ΓåÆ "~260.000 VND"
 */
export function formatVndEquivalent(usdPrice: number): string {
    const vnd = Math.round((usdPrice || 0) * USD_TO_VND_RATE);
    return `~${new Intl.NumberFormat("vi-VN").format(vnd)} VND`;
}

export function parsePrice(priceString: string): number {
    const cleaned = priceString.replace(/[^\d.-]/g, "");
    return Number.parseFloat(cleaned) || 0;
}

/**
 * LIKEFOOD - Vietnamese Specialty Marketplace
 * OBS-001: Structured Logging System
 *
 * Replaces ad-hoc console.log with JSON structured logs.
 * Adds: correlation IDs, log levels, context, timestamps.
 *
 * Usage:
 *   import { structuredLogger } from "@/lib/structured-logger";
 *   structuredLogger.info("Order created", { orderId, userId });
 *   structuredLogger.error("Payment failed", error, { orderId });
 */

type LogLevel = "debug" | "info" | "warn" | "error" | "security";
type LogMeta = Record<string, unknown>;

interface LogEntry {
    timestamp: string;
    level: LogLevel;
    message: string;
    context?: string;
    correlationId?: string;
    error?: {
        name: string;
        message: string;
        stack?: string;
    };
    meta?: LogMeta;
    service: string;
    environment: string;
}

const SERVICE_NAME = "likefood";
const ENV = process.env.NODE_ENV || "development";
const isProduction = ENV === "production";

// Simple correlation ID generator
let correlationSeq = 0;
export function generateCorrelationId(): string {
    return `${Date.now()}-${++correlationSeq}`;
}

function formatEntry(
    level: LogLevel,
    message: string,
    error?: Error | null,
    meta?: LogMeta
): LogEntry {
    const entry: LogEntry = {
        timestamp: new Date().toISOString(),
        level,
        message,
        service: SERVICE_NAME,
        environment: ENV,
    };

    if (meta?.context) {
        entry.context = meta.context as string;
        const { context, ...rest } = meta;
        if (Object.keys(rest).length > 0) {
            entry.meta = rest;
        }
    } else if (meta && Object.keys(meta).length > 0) {
        entry.meta = meta;
    }

    if (meta?.correlationId) {
        entry.correlationId = meta.correlationId as string;
    }

    if (error) {
        entry.error = {
            name: error.name,
            message: error.message,
            ...(isProduction ? {} : { stack: error.stack }),
        };
    }

    return entry;
}

function emit(entry: LogEntry): void {
    const output = isProduction
        ? JSON.stringify(entry)
        : `[${entry.level.toUpperCase()}] ${entry.message}${entry.error ? ` | ${entry.error.message}` : ""}${entry.meta ? ` | ${JSON.stringify(entry.meta)}` : ""}`;

    switch (entry.level) {
        case "error":
        case "security":
            console.error(output);
            break;
        case "warn":
            console.warn(output);
            break;
        case "debug":
            if (!isProduction) console.log(output);
            break;
        default:
            console.log(output);
    }
}

export const structuredLogger = {
    debug(message: string, meta?: LogMeta) {
        if (!isProduction) emit(formatEntry("debug", message, null, meta));
    },

    info(message: string, meta?: LogMeta) {
        emit(formatEntry("info", message, null, meta));
    },

    warn(message: string, meta?: LogMeta) {
        emit(formatEntry("warn", message, null, meta));
    },

    error(message: string, error?: Error | null, meta?: LogMeta) {
        emit(formatEntry("error", message, error, meta));
    },

    security(message: string, meta?: LogMeta) {
        emit(formatEntry("security", `[SECURITY] ${message}`, null, meta));
    },
};

